// sr_physics.js — 200 questions (Years 11-12)
const Q_SR_PHYSICS=[{"id": "srp111001", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Kinematics", "difficulty": "hard", "style": "standard", "paper": "G11-P1", "q": "A car starts at 5 m/s and accelerates at 3 m/s² for 4 seconds. Using v = u + at, what is its final velocity?", "options": ["12 m/s", "17 m/s", "20 m/s", "32 m/s"], "answer": 1, "exp": "Step 1: v = u + at. Step 2: v = 5 + (3 × 4) = 5 + 12 = 17 m/s.", "hint": "Substitute u, a and t directly into the equation v = u + at."}, {"id": "srp111002", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Kinematics", "difficulty": "hard", "style": "standard", "paper": "G11-P1", "q": "A car starts at 5 m/s and accelerates at 3 m/s² for 4 seconds. Using s = ut + ½at², what distance does it travel?", "options": ["32 m", "38 m", "44 m", "52 m"], "answer": 2, "exp": "Step 1: s = ut + ½at² = (5×4) + ½(3)(4²). Step 2: 20 + ½(3)(16) = 20 + 24 = 44 m.", "hint": "Substitute u, a and t into the equation s = ut + ½at², being careful with order of operations."}, {"id": "srp111003", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Kinematics", "difficulty": "hard", "style": "standard", "paper": "G11-P1", "q": "An object starts from rest and accelerates at 4 m/s² over a distance of 20 m. Using v² = u² + 2as, what is its final velocity (to 1 decimal place)?", "options": ["8.9 m/s", "11.3 m/s", "12.6 m/s", "16.0 m/s"], "answer": 2, "exp": "Step 1: v² = u² + 2as = 0² + 2(4)(20) = 160. Step 2: v = √160 ≈ 12.6 m/s.", "hint": "Substitute into v² = u² + 2as, then take the square root."}, {"id": "srp111004", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Kinematics", "difficulty": "hard", "style": "standard", "paper": "G11-P1", "q": "A runner covers 100 m in 8 seconds at a constant velocity. What is their average velocity?", "options": ["8 m/s", "12.5 m/s", "16 m/s", "100 m/s"], "answer": 1, "exp": "Step 1: Average velocity = displacement ÷ time. Step 2: 100 ÷ 8 = 12.5 m/s.", "hint": "Divide the total displacement by the total time."}, {"id": "srp111005", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Vectors", "difficulty": "hard", "style": "standard", "paper": "G11-P1", "q": "Two perpendicular vector components are 3 N (horizontal) and 4 N (vertical). What is the magnitude of the resultant vector?", "options": ["3.5 N", "4.5 N", "5 N", "7 N"], "answer": 2, "exp": "Step 1: Use Pythagoras' theorem for perpendicular components: magnitude = √(3² + 4²). Step 2: √(9+16) = √25 = 5 N.", "hint": "Treat the two perpendicular components as the legs of a right-angled triangle."}, {"id": "srp111006", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Vectors", "difficulty": "hard", "style": "standard", "paper": "G11-P1", "q": "For the same vector (3 N horizontal, 4 N vertical), what is the angle of the resultant above the horizontal, to the nearest degree?", "options": ["37°", "45°", "53°", "60°"], "answer": 2, "exp": "Step 1: angle = tan⁻¹(vertical ÷ horizontal) = tan⁻¹(4/3). Step 2: This gives approximately 53°.", "hint": "Use the inverse tangent of (vertical component ÷ horizontal component)."}, {"id": "srp111007", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Newton's Laws", "difficulty": "hard", "style": "standard", "paper": "G11-P1", "q": "A net force of 10 N is applied to a 5 kg object. Using F = ma, what is its acceleration?", "options": ["0.5 m/s²", "2 m/s²", "5 m/s²", "50 m/s²"], "answer": 1, "exp": "Step 1: F = ma, so a = F ÷ m. Step 2: 10 ÷ 5 = 2 m/s².", "hint": "Rearrange F = ma to solve for acceleration."}, {"id": "srp111008", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Forces", "difficulty": "hard", "style": "standard", "paper": "G11-P1", "q": "What is the weight of a 10 kg object, using g ≈ 9.8 m/s²?", "options": ["10 N", "49 N", "98 N", "980 N"], "answer": 2, "exp": "Step 1: Weight = mass × g. Step 2: 10 × 9.8 = 98 N.", "hint": "Multiply the mass by the gravitational acceleration."}, {"id": "srp111009", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Momentum", "difficulty": "hard", "style": "standard", "paper": "G11-P1", "q": "A 4 kg object moves at 6 m/s. What is its momentum?", "options": ["1.5 kg·m/s", "10 kg·m/s", "24 kg·m/s", "36 kg·m/s"], "answer": 2, "exp": "Step 1: Momentum = mass × velocity. Step 2: 4 × 6 = 24 kg·m/s.", "hint": "Multiply the object's mass by its velocity."}, {"id": "srp111010", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Momentum — Impulse", "difficulty": "hard", "style": "standard", "paper": "G11-P1", "q": "A force of 10 N is applied to an object for 0.5 seconds. What is the impulse delivered?", "options": ["2 N·s", "5 N·s", "10 N·s", "20 N·s"], "answer": 1, "exp": "Step 1: Impulse = force × time. Step 2: 10 × 0.5 = 5 N·s.", "hint": "Multiply the force by the time over which it acts."}, {"id": "srp111011", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Newton's Laws", "difficulty": "hard", "style": "standard", "paper": "G11-P1", "q": "Which of these correctly states Newton's first law of motion?", "options": ["force equals mass times acceleration", "an object's velocity remains unchanged unless acted on by a net external force", "every action has an equal and opposite reaction", "objects always fall at the same rate regardless of mass"], "answer": 1, "exp": "Newton's first law (the law of inertia) states that an object's velocity remains unchanged (it continues at constant velocity, including zero) unless acted on by a net external force.", "hint": "This law describes an object's natural tendency to resist changes in motion."}, {"id": "srp111012", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Newton's Laws", "difficulty": "hard", "style": "standard", "paper": "G11-P1", "q": "Which of these correctly states Newton's third law of motion?", "options": ["objects at rest stay at rest", "force equals mass multiplied by acceleration", "for every action force, there is an equal and opposite reaction force", "heavier objects always experience greater gravitational acceleration"], "answer": 2, "exp": "Newton's third law states that for every action force exerted by one object on another, there is an equal and opposite reaction force exerted back.", "hint": "Think about paired forces — one action, one equal and opposite reaction."}, {"id": "srp111013", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Projectile Motion", "difficulty": "hard", "style": "standard", "paper": "G11-P1", "q": "A ball is thrown horizontally from a height and undergoes projectile motion (ignoring air resistance). What happens to its horizontal velocity during the flight?", "options": ["it increases steadily due to gravity", "it decreases steadily due to gravity", "it remains constant, since gravity acts only vertically", "it becomes zero immediately"], "answer": 2, "exp": "Since gravity acts only vertically (downward), the horizontal velocity component of a projectile remains constant throughout its flight, assuming no air resistance.", "hint": "Think about which direction gravity acts in, and whether that affects horizontal motion."}, {"id": "srp111014", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Projectile Motion", "difficulty": "hard", "style": "standard", "paper": "G11-P1", "q": "A projectile is launched horizontally from a height of 20 m. Using h = ½gt² (with g ≈ 9.8 m/s²), approximately how long does it take to hit the ground?", "options": ["1.4 s", "2.0 s", "2.9 s", "4.1 s"], "answer": 1, "exp": "Step 1: 20 = ½(9.8)t². Step 2: t² = 40/9.8 ≈ 4.08. Step 3: t ≈ √4.08 ≈ 2.0 s.", "hint": "Rearrange the equation to solve for t, then take the square root."}, {"id": "srp111015", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Forces — Gravity", "difficulty": "hard", "style": "standard", "paper": "G11-P1", "q": "Two objects, one with mass 2 kg and one with mass 8 kg, are dropped from the same height in a vacuum (no air resistance). Which lands first?", "options": ["the 2 kg object", "the 8 kg object", "both land at exactly the same time", "it cannot be determined without more information"], "answer": 2, "exp": "In a vacuum, all objects experience the same gravitational acceleration regardless of mass, so both objects land at exactly the same time when dropped from the same height.", "hint": "Think about why mass cancels out when calculating gravitational acceleration."}, {"id": "srp111016", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Newton's Laws", "difficulty": "hard", "style": "standard", "paper": "G11-P1", "q": "A 1000 kg car travelling at 20 m/s comes to a stop in 5 seconds. What average force was required to stop it?", "options": ["1000 N", "2000 N", "4000 N", "5000 N"], "answer": 2, "exp": "Step 1: Acceleration = (0-20)/5 = -4 m/s². Step 2: Force = ma = 1000 × 4 = 4000 N (magnitude).", "hint": "Find the deceleration first, then apply F = ma."}, {"id": "srp111017", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Vectors", "difficulty": "hard", "style": "standard", "paper": "G11-P1", "q": "What is the difference between scalar and vector quantities?", "options": ["scalars have both magnitude and direction, while vectors have only magnitude", "vectors have both magnitude and direction, while scalars have only magnitude", "scalars and vectors are exactly the same thing", "vectors can only be used to describe forces"], "answer": 1, "exp": "Vectors have both magnitude and direction (such as velocity or force), while scalars have only magnitude (such as speed or mass).", "hint": "Think about which of these two quantity types includes a directional component."}, {"id": "srp111018", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Vectors", "difficulty": "hard", "style": "standard", "paper": "G11-P1", "q": "Two forces of 6 N and 8 N act on an object at right angles to each other. What is the magnitude of the resultant force?", "options": ["7 N", "10 N", "14 N", "48 N"], "answer": 1, "exp": "Step 1: Use Pythagoras' theorem: resultant = √(6² + 8²). Step 2: √(36+64) = √100 = 10 N.", "hint": "Treat the two perpendicular forces as the legs of a right-angled triangle."}, {"id": "srp111019", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Kinematics", "difficulty": "hard", "style": "standard", "paper": "G11-P1", "q": "A car accelerates uniformly from 10 m/s to 30 m/s over 50 m. Using v² = u² + 2as, what is its acceleration?", "options": ["2 m/s²", "4 m/s²", "6 m/s²", "8 m/s²"], "answer": 3, "exp": "Step 1: v² = u² + 2as → 30² = 10² + 2a(50). Step 2: 900 = 100 + 100a. Step 3: 800 = 100a, so a = 8 m/s².", "hint": "Rearrange v² = u² + 2as to solve for acceleration."}, {"id": "srp111020", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Newton's Laws", "difficulty": "hard", "style": "standard", "paper": "G11-P1", "q": "Which best explains why a passenger feels pushed backward into their seat as a car accelerates forward?", "options": ["a real backward force is pushing them", "due to inertia, their body resists the forward acceleration unless an external force (the seat) provides it", "gravity increases during acceleration", "this is purely an imagined sensation with no physical explanation"], "answer": 1, "exp": "Due to inertia, a passenger's body tends to resist the change in motion (the car's forward acceleration). The seat provides the actual forward force needed to accelerate the passenger along with the car, which feels like being pushed back relative to the car's frame.", "hint": "Think about Newton's first law — the body resists changes to its motion unless a force acts on it."}, {"id": "srp111021", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Newton's Laws", "difficulty": "hard", "style": "standard", "paper": "G11-P1", "q": "A 1500 kg car experiences a braking force of 6000 N. What deceleration does this produce?", "options": ["2 m/s²", "4 m/s²", "6 m/s²", "9 m/s²"], "answer": 1, "exp": "Step 1: a = F ÷ m. Step 2: 6000 ÷ 1500 = 4 m/s².", "hint": "Rearrange F = ma to solve for acceleration."}, {"id": "srp111022", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Momentum", "difficulty": "hard", "style": "standard", "paper": "G11-P1", "q": "What is the SI unit for momentum?", "options": ["newton (N)", "joule (J)", "kilogram metres per second (kg·m/s)", "watt (W)"], "answer": 2, "exp": "Momentum is measured in kilogram metres per second (kg·m/s), reflecting its definition as mass × velocity.", "hint": "Think about the units that result from multiplying mass (kg) by velocity (m/s)."}, {"id": "srp111023", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Momentum — Conservation", "difficulty": "hard", "style": "standard", "paper": "G11-P1", "q": "In a collision between two objects with no external forces, what does the law of conservation of momentum state?", "options": ["momentum is always lost during a collision", "the total momentum of the system before the collision equals the total momentum after the collision", "momentum only applies to elastic collisions", "momentum is converted entirely into heat during every collision"], "answer": 1, "exp": "The law of conservation of momentum states that, in the absence of external forces, the total momentum of a system before a collision equals the total momentum after the collision.", "hint": "Think about what stays the same (is 'conserved') throughout an isolated collision."}, {"id": "srp111024", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Momentum — Conservation", "difficulty": "hard", "style": "standard", "paper": "G11-P1", "q": "Two ice skaters, initially at rest, push off from each other. Skater A (50 kg) moves left at 2 m/s. Using conservation of momentum, what speed does Skater B (40 kg) move at (in the opposite direction)?", "options": ["1.6 m/s", "2.0 m/s", "2.5 m/s", "4.0 m/s"], "answer": 2, "exp": "Step 1: Total momentum before = 0 (both at rest). Step 2: 50×2 = 40×v (momentum must balance in opposite directions). Step 3: v = 100/40 = 2.5 m/s.", "hint": "Since total momentum starts at zero, the two skaters' momenta must be equal in size but opposite in direction."}, {"id": "srp111025", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Kinematics", "difficulty": "hard", "style": "standard", "paper": "G11-P1", "q": "An object is dropped from a height of 45 m. Using h = ½gt² (with g ≈ 9.8 m/s²), approximately how long does it take to reach the ground?", "options": ["2.1 s", "3.0 s", "3.8 s", "4.5 s"], "answer": 1, "exp": "Step 1: 45 = ½(9.8)t². Step 2: t² = 90/9.8 ≈ 9.18. Step 3: t ≈ √9.18 ≈ 3.0 s.", "hint": "Rearrange the equation to solve for t, then take the square root."}, {"id": "srp112001", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Work and Energy", "difficulty": "hard", "style": "standard", "paper": "G11-P2", "q": "A force of 20 N moves an object 5 m in the direction of the force. How much work is done?", "options": ["4 J", "25 J", "100 J", "100 N"], "answer": 2, "exp": "Step 1: Work = force × distance. Step 2: 20 × 5 = 100 J.", "hint": "Multiply the force by the distance moved in the direction of that force."}, {"id": "srp112002", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Energy — Kinetic", "difficulty": "hard", "style": "standard", "paper": "G11-P2", "q": "A 4 kg object moves at 10 m/s. What is its kinetic energy?", "options": ["40 J", "100 J", "200 J", "400 J"], "answer": 2, "exp": "Step 1: KE = ½mv². Step 2: ½(4)(10²) = ½(4)(100) = 200 J.", "hint": "Use the formula: kinetic energy = half × mass × velocity squared."}, {"id": "srp112003", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Energy — Potential", "difficulty": "hard", "style": "standard", "paper": "G11-P2", "q": "A 5 kg object is raised 10 m above the ground. Using g ≈ 9.8 m/s², what is its gravitational potential energy?", "options": ["49 J", "98 J", "490 J", "980 J"], "answer": 2, "exp": "Step 1: GPE = mgh. Step 2: 5 × 9.8 × 10 = 490 J.", "hint": "Use the formula: GPE = mass × gravitational acceleration × height."}, {"id": "srp112004", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Power", "difficulty": "hard", "style": "standard", "paper": "G11-P2", "q": "A machine does 500 J of work in 10 seconds. What is its power output?", "options": ["5 W", "50 W", "500 W", "5000 W"], "answer": 1, "exp": "Step 1: Power = work ÷ time. Step 2: 500 ÷ 10 = 50 W.", "hint": "Divide the work done by the time taken."}, {"id": "srp112005", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Power", "difficulty": "hard", "style": "standard", "paper": "G11-P2", "q": "A car engine exerts a driving force of 200 N at a constant velocity of 15 m/s. What is the power output?", "options": ["13.3 W", "185 W", "3000 W", "30000 W"], "answer": 2, "exp": "Step 1: Power = force × velocity. Step 2: 200 × 15 = 3000 W.", "hint": "Use the formula: power = force × velocity, valid at constant speed."}, {"id": "srp112006", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Energy — Efficiency", "difficulty": "hard", "style": "standard", "paper": "G11-P2", "q": "A machine receives 250 J of input energy and produces 200 J of useful output energy. What is its efficiency?", "options": ["50%", "65%", "80%", "125%"], "answer": 2, "exp": "Step 1: Efficiency = (useful output ÷ total input) × 100. Step 2: (200 ÷ 250) × 100 = 80%.", "hint": "Divide the useful output energy by the total input energy, then convert to a percentage."}, {"id": "srp112007", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Energy — Elastic Potential", "difficulty": "hard", "style": "standard", "paper": "G11-P2", "q": "A spring with spring constant 200 N/m is compressed by 0.1 m. Using Eₚ = ½kx², what elastic potential energy is stored?", "options": ["0.5 J", "1.0 J", "2.0 J", "20 J"], "answer": 1, "exp": "Step 1: Eₚ = ½kx². Step 2: ½(200)(0.1²) = ½(200)(0.01) = 1.0 J.", "hint": "Use the formula: elastic potential energy = half × spring constant × extension squared."}, {"id": "srp112008", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Circular Motion", "difficulty": "hard", "style": "standard", "paper": "G11-P2", "q": "An object moves in a circle of radius 5 m, completing one full revolution every 4 seconds. Using v = 2πr/T, what is its speed (to 1 decimal place)?", "options": ["3.9 m/s", "6.3 m/s", "7.9 m/s", "12.5 m/s"], "answer": 2, "exp": "Step 1: v = 2πr/T = (2 × π × 5) ÷ 4. Step 2: This gives approximately 7.9 m/s.", "hint": "Substitute the radius and period into v = 2πr/T."}, {"id": "srp112009", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Circular Motion", "difficulty": "hard", "style": "standard", "paper": "G11-P2", "q": "An object moves in a circle of radius 5 m at a speed of 10 m/s. Using a = v²/r, what is its centripetal acceleration?", "options": ["2 m/s²", "10 m/s²", "20 m/s²", "50 m/s²"], "answer": 2, "exp": "Step 1: a = v²/r = 10²/5. Step 2: 100/5 = 20 m/s².", "hint": "Substitute the speed and radius into a = v²/r."}, {"id": "srp112010", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Circular Motion", "difficulty": "hard", "style": "standard", "paper": "G11-P2", "q": "A 2 kg object moves in a circle of radius 5 m at 10 m/s. Using F = mv²/r, what centripetal force is required?", "options": ["4 N", "20 N", "40 N", "200 N"], "answer": 2, "exp": "Step 1: F = mv²/r = (2 × 10²) ÷ 5. Step 2: (2 × 100) ÷ 5 = 40 N.", "hint": "Substitute mass, speed and radius into F = mv²/r."}, {"id": "srp112011", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Circular Motion", "difficulty": "hard", "style": "standard", "paper": "G11-P2", "q": "In which direction does centripetal force always point, for an object moving in a circle?", "options": ["tangent to the circle, in the direction of motion", "directly outward, away from the centre", "directly inward, toward the centre of the circle", "centripetal force has no fixed direction"], "answer": 2, "exp": "Centripetal force always points directly inward, toward the centre of the circular path, which is what keeps the object moving in a circle rather than a straight line.", "hint": "Think about the force needed to constantly redirect an object's motion toward the centre."}, {"id": "srp112012", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Energy — Conservation", "difficulty": "hard", "style": "standard", "paper": "G11-P2", "q": "Which best describes the law of conservation of energy?", "options": ["energy can be created but never destroyed", "energy can be destroyed but never created", "energy cannot be created or destroyed, only transformed from one form to another", "energy is always lost completely in any process"], "answer": 2, "exp": "The law of conservation of energy states that energy cannot be created or destroyed — it can only be transformed from one form into another, such as from gravitational potential energy into kinetic energy.", "hint": "Think about energy changing form, rather than disappearing or appearing from nothing."}, {"id": "srp112013", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Energy — Conservation", "difficulty": "hard", "style": "standard", "paper": "G11-P2", "q": "A ball of mass 2 kg is dropped from a height of 10 m. Using conservation of energy (ignoring air resistance) and g ≈ 9.8 m/s², approximately what is its speed just before hitting the ground?", "options": ["9.9 m/s", "14 m/s", "19.6 m/s", "98 m/s"], "answer": 1, "exp": "Step 1: GPE lost = KE gained: mgh = ½mv². Step 2: gh = ½v², so v² = 2gh = 2(9.8)(10) = 196. Step 3: v = √196 = 14 m/s.", "hint": "Set gravitational potential energy lost equal to kinetic energy gained, then solve for v."}, {"id": "srp112014", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Energy — Conservation", "difficulty": "hard", "style": "standard", "paper": "G11-P2", "q": "A roller coaster car has the most kinetic energy at which point of a hill-shaped track?", "options": ["at the very top of the hill", "at the very bottom of the hill", "kinetic energy is the same at every point", "kinetic energy cannot be determined from position alone"], "answer": 1, "exp": "At the bottom of the hill, the car has converted the most gravitational potential energy into kinetic energy, giving it the highest kinetic energy (and speed) at that point.", "hint": "Think about where the car is moving fastest, given its height has decreased the most."}, {"id": "srp112015", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Power", "difficulty": "hard", "style": "standard", "paper": "G11-P2", "q": "What is the SI unit for power?", "options": ["joule (J)", "newton (N)", "watt (W)", "kilogram (kg)"], "answer": 2, "exp": "Power is measured in watts (W), where 1 watt equals 1 joule of energy transferred per second.", "hint": "This unit is named after a Scottish engineer famous for his work on the steam engine."}, {"id": "srp112016", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Energy and Work", "difficulty": "hard", "style": "standard", "paper": "G11-P2", "q": "What is the SI unit for energy and work?", "options": ["watt (W)", "joule (J)", "newton (N)", "pascal (Pa)"], "answer": 1, "exp": "Both energy and work are measured in joules (J).", "hint": "This unit shares its name between energy and the work done by a force."}, {"id": "srp112017", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Energy — Conservation", "difficulty": "hard", "style": "standard", "paper": "G11-P2", "q": "A pendulum swings from its highest point (maximum height, zero speed) to its lowest point. What energy transformation occurs?", "options": ["kinetic energy transforms into gravitational potential energy", "gravitational potential energy transforms into kinetic energy", "chemical energy transforms into kinetic energy", "no energy transformation occurs"], "answer": 1, "exp": "As the pendulum swings from its highest point to its lowest point, its gravitational potential energy (due to height) transforms into kinetic energy (due to motion).", "hint": "Think about what happens to the pendulum's height and speed as it swings downward."}, {"id": "srp112018", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Energy — Efficiency", "difficulty": "hard", "style": "standard", "paper": "G11-P2", "q": "A car uses 40,000 J of chemical energy from fuel to do 10,000 J of useful work moving the car forward. What is the engine's efficiency?", "options": ["15%", "25%", "40%", "75%"], "answer": 1, "exp": "Step 1: Efficiency = (useful output ÷ total input) × 100. Step 2: (10000 ÷ 40000) × 100 = 25%.", "hint": "Divide the useful output energy by the total input energy, then convert to a percentage."}, {"id": "srp112019", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Circular Motion", "difficulty": "hard", "style": "standard", "paper": "G11-P2", "q": "An object moving in uniform circular motion has a constant speed. Why does it still have a non-zero acceleration?", "options": ["acceleration always requires a change in speed only", "its direction is continuously changing, and acceleration depends on change in velocity (a vector), not just speed", "this object actually has zero acceleration", "acceleration cannot occur during circular motion"], "answer": 1, "exp": "Even though speed is constant, the object's direction is continuously changing, which means its velocity (a vector quantity including direction) is changing — and a change in velocity is acceleration, even without a change in speed.", "hint": "Remember that velocity includes direction, not just speed — and acceleration is about change in velocity."}, {"id": "srp112020", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Power", "difficulty": "hard", "style": "standard", "paper": "G11-P2", "q": "A lift (elevator) raises a 500 kg load a height of 20 m in 25 seconds. Using g ≈ 9.8 m/s², what is the average power required?", "options": ["3,920 W", "4,900 W", "6,125 W", "9,800 W"], "answer": 0, "exp": "Step 1: Work done = mgh = 500 × 9.8 × 20 = 98,000 J. Step 2: Power = work ÷ time = 98,000 ÷ 25 = 3,920 W.", "hint": "Calculate the total work done against gravity first, then divide by the time taken."}, {"id": "srp112021", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Energy — Efficiency", "difficulty": "hard", "style": "standard", "paper": "G11-P2", "q": "Which best explains why real machines are never 100% efficient?", "options": ["all machines are perfectly efficient in practice", "some input energy is always converted to non-useful forms, typically heat, due to factors like friction", "efficiency calculations are never accurate", "machines only become inefficient over very long periods of use"], "answer": 1, "exp": "Real machines are never 100% efficient because some input energy is always converted into non-useful forms, typically heat, due to factors like friction and air resistance.", "hint": "Think about where some of the input energy 'leaks away' to, rather than doing useful work."}, {"id": "srp112022", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Energy — Kinetic", "difficulty": "hard", "style": "standard", "paper": "G11-P2", "q": "A 1500 kg car travelling at 20 m/s brakes to a stop. How much kinetic energy must be dissipated (mostly as heat in the brakes)?", "options": ["150,000 J", "300,000 J", "600,000 J", "900,000 J"], "answer": 1, "exp": "Step 1: KE = ½mv². Step 2: ½(1500)(20²) = ½(1500)(400) = 300,000 J.", "hint": "Use the kinetic energy formula with the car's mass and initial speed."}, {"id": "srp112023", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Circular Motion", "difficulty": "hard", "style": "standard", "paper": "G11-P2", "q": "A satellite orbits Earth in a circular path at constant speed. What provides the centripetal force needed to maintain this orbit?", "options": ["the satellite's own engines, firing continuously", "gravitational attraction between the satellite and Earth", "friction with the upper atmosphere", "there is no centripetal force acting on an orbiting satellite"], "answer": 1, "exp": "Gravitational attraction between the satellite and Earth provides the centripetal force needed to continuously redirect the satellite's motion, keeping it in a circular orbit.", "hint": "Think about the force that naturally pulls the satellite toward Earth's centre."}, {"id": "srp112024", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Energy — Transformations", "difficulty": "hard", "style": "standard", "paper": "G11-P2", "q": "Which of these correctly ranks the energy transformations as a battery-powered torch is switched on?", "options": ["light energy → chemical energy → electrical energy", "chemical energy → electrical energy → light energy (and some heat)", "electrical energy → chemical energy → light energy", "heat energy → chemical energy → light energy"], "answer": 1, "exp": "A battery stores chemical energy, which is converted into electrical energy to power the torch, which is then converted into light energy (along with some heat as a by-product).", "hint": "Think about the form of energy stored in a battery before any transformation occurs."}, {"id": "srp112025", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Power", "difficulty": "hard", "style": "standard", "paper": "G11-P2", "q": "A cyclist does 3000 J of work over 1 minute. What is their average power output?", "options": ["3 W", "30 W", "50 W", "3000 W"], "answer": 2, "exp": "Step 1: Convert time to seconds: 1 minute = 60 s. Step 2: Power = work ÷ time = 3000 ÷ 60 = 50 W.", "hint": "Make sure to convert the time into seconds before dividing."}, {"id": "srp113001", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Waves", "difficulty": "hard", "style": "standard", "paper": "G11-P3", "q": "A wave has a frequency of 50 Hz and a wavelength of 2 m. Using v = fλ, what is its speed?", "options": ["25 m/s", "52 m/s", "100 m/s", "200 m/s"], "answer": 2, "exp": "Step 1: v = fλ. Step 2: 50 × 2 = 100 m/s.", "hint": "Multiply the frequency by the wavelength."}, {"id": "srp113002", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Waves", "difficulty": "hard", "style": "standard", "paper": "G11-P3", "q": "A wave travels at 340 m/s with a wavelength of 0.5 m. Using f = v/λ, what is its frequency?", "options": ["170 Hz", "340 Hz", "680 Hz", "1700 Hz"], "answer": 2, "exp": "Step 1: f = v/λ. Step 2: 340 ÷ 0.5 = 680 Hz.", "hint": "Divide the wave speed by the wavelength."}, {"id": "srp113003", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Waves", "difficulty": "hard", "style": "standard", "paper": "G11-P3", "q": "A wave travels at 340 m/s with a frequency of 170 Hz. Using λ = v/f, what is its wavelength?", "options": ["0.5 m", "1 m", "2 m", "4 m"], "answer": 2, "exp": "Step 1: λ = v/f. Step 2: 340 ÷ 170 = 2 m.", "hint": "Divide the wave speed by the frequency."}, {"id": "srp113004", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Waves", "difficulty": "hard", "style": "standard", "paper": "G11-P3", "q": "A wave has a frequency of 20 Hz. Using T = 1/f, what is its period?", "options": ["0.02 s", "0.05 s", "2 s", "20 s"], "answer": 1, "exp": "Step 1: T = 1/f. Step 2: 1 ÷ 20 = 0.05 s.", "hint": "The period is the reciprocal of the frequency."}, {"id": "srp113005", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Waves", "difficulty": "hard", "style": "standard", "paper": "G11-P3", "q": "A wave has a period of 0.02 s. Using f = 1/T, what is its frequency?", "options": ["0.5 Hz", "2 Hz", "20 Hz", "50 Hz"], "answer": 3, "exp": "Step 1: f = 1/T. Step 2: 1 ÷ 0.02 = 50 Hz.", "hint": "The frequency is the reciprocal of the period."}, {"id": "srp113006", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Waves — Types", "difficulty": "hard", "style": "standard", "paper": "G11-P3", "q": "Which best describes a 'transverse wave'?", "options": ["a wave where particles vibrate parallel to the direction of energy transfer", "a wave where particles vibrate perpendicular to the direction of energy transfer", "a wave that can only travel through a vacuum", "a wave with no measurable wavelength"], "answer": 1, "exp": "In a transverse wave, particles vibrate perpendicular (at right angles) to the direction the wave's energy travels, such as in light waves or a wave on a string.", "hint": "Think about the particles moving up-and-down or side-to-side, while the wave itself travels forward."}, {"id": "srp113007", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Waves — Types", "difficulty": "hard", "style": "standard", "paper": "G11-P3", "q": "Which best describes a 'longitudinal wave'?", "options": ["a wave where particles vibrate perpendicular to the direction of energy transfer", "a wave where particles vibrate parallel to the direction of energy transfer", "a wave that only exists in solids", "a wave with no defined frequency"], "answer": 1, "exp": "In a longitudinal wave, particles vibrate parallel to (in the same direction as) the direction of energy transfer, such as in sound waves.", "hint": "Think about particles moving back and forth in the SAME direction the wave is travelling."}, {"id": "srp113008", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Sound", "difficulty": "hard", "style": "standard", "paper": "G11-P3", "q": "Is sound a transverse or longitudinal wave?", "options": ["transverse", "longitudinal", "sound is not a wave at all", "sound can be either, depending on the medium"], "answer": 1, "exp": "Sound is a longitudinal wave, since air particles vibrate back and forth parallel to the direction the sound travels.", "hint": "Think about how air particles compress and expand along the same direction the sound moves."}, {"id": "srp113009", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Sound", "difficulty": "hard", "style": "standard", "paper": "G11-P3", "q": "Why can't sound travel through a vacuum (such as outer space)?", "options": ["sound waves are destroyed by sunlight in space", "sound requires a medium (particles) to vibrate through, and a vacuum contains no particles", "sound only exists on Earth", "sound actually can travel through a vacuum"], "answer": 1, "exp": "Sound is a mechanical wave that requires a medium (such as air, water, or a solid) to transfer vibrations between particles. A vacuum contains no particles, so sound cannot travel through it.", "hint": "Think about what sound actually needs to travel — and what's missing in a vacuum."}, {"id": "srp113010", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Sound", "difficulty": "hard", "style": "standard", "paper": "G11-P3", "q": "Two students measure the time it takes for an echo to return from a cliff 340 m away. If sound travels at 340 m/s, how long should the echo take to return (round trip)?", "options": ["0.5 s", "1 s", "2 s", "4 s"], "answer": 2, "exp": "Step 1: Total distance travelled by sound = 340 × 2 = 680 m (there and back). Step 2: Time = distance ÷ speed = 680 ÷ 340 = 2 s.", "hint": "Remember the sound must travel to the cliff AND back, doubling the distance."}, {"id": "srp113011", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Sound", "difficulty": "hard", "style": "standard", "paper": "G11-P3", "q": "What determines the pitch of a sound wave?", "options": ["its amplitude", "its frequency", "its speed only", "its wavelength has no connection to pitch"], "answer": 1, "exp": "Pitch is determined by frequency — higher frequency waves are perceived as higher pitched sounds.", "hint": "Think about how fast something vibrates, which directly relates to how high or low it sounds."}, {"id": "srp113012", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Sound", "difficulty": "hard", "style": "standard", "paper": "G11-P3", "q": "What determines the loudness of a sound wave?", "options": ["its frequency", "its amplitude", "its wavelength only", "the colour of the source"], "answer": 1, "exp": "Loudness is determined by amplitude — larger amplitude waves carry more energy and are perceived as louder.", "hint": "Think about the size of the vibration, which relates to the energy carried by the wave."}, {"id": "srp113013", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Waves — Doppler Effect", "difficulty": "hard", "style": "standard", "paper": "G11-P3", "q": "Which best describes the 'Doppler effect'?", "options": ["the apparent change in frequency of a wave due to relative motion between the source and the observer", "a wave's amplitude decreasing over distance", "the bending of waves around obstacles", "the splitting of white light into colours"], "answer": 0, "exp": "The Doppler effect describes the apparent change in frequency (and pitch, for sound) of a wave due to relative motion between the wave's source and the observer, such as a siren sounding higher pitched as it approaches.", "hint": "Think about why a passing ambulance's siren seems to change pitch as it approaches and then moves away."}, {"id": "srp113014", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Waves — Doppler Effect", "difficulty": "hard", "style": "standard", "paper": "G11-P3", "q": "As a sound source moves TOWARD a stationary observer, what happens to the observed frequency (pitch)?", "options": ["it decreases", "it increases", "it remains exactly the same", "frequency is unrelated to relative motion"], "answer": 1, "exp": "As a sound source moves toward an observer, sound waves are compressed (bunched closer together), increasing the observed frequency and resulting in a higher perceived pitch.", "hint": "Think about the waves being 'squashed together' as the source approaches."}, {"id": "srp113015", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Waves", "difficulty": "hard", "style": "standard", "paper": "G11-P3", "q": "Which best describes 'diffraction' of waves?", "options": ["the bending of waves as they pass through a gap or around an obstacle", "the bouncing of waves off a surface", "the splitting of a wave into multiple colours", "the complete absorption of a wave by a medium"], "answer": 0, "exp": "Diffraction is the bending or spreading of waves as they pass through a gap or around an obstacle.", "hint": "Think about waves spreading out after passing through a narrow opening, like a doorway."}, {"id": "srp113016", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Waves", "difficulty": "hard", "style": "standard", "paper": "G11-P3", "q": "Which best describes 'refraction' of waves?", "options": ["waves bouncing directly back off a surface", "waves changing speed and direction as they pass from one medium into another", "waves cancelling each other out completely", "waves only occurring in water"], "answer": 1, "exp": "Refraction is the change in speed and direction of a wave as it passes from one medium into another, due to a change in wave speed.", "hint": "Think about why a wave bends when it crosses into a different material, like light entering water."}, {"id": "srp113017", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Waves — Interference", "difficulty": "hard", "style": "standard", "paper": "G11-P3", "q": "Which best describes 'constructive interference' between two waves?", "options": ["the waves combine to produce a smaller resultant wave", "the waves combine in phase to produce a larger resultant wave", "the waves cancel each other out completely", "interference can never increase a wave's amplitude"], "answer": 1, "exp": "Constructive interference occurs when two waves combine in phase (crest aligning with crest), producing a resultant wave with a larger amplitude than either individual wave.", "hint": "Think about two waves' peaks lining up perfectly, adding together rather than cancelling."}, {"id": "srp113018", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Waves — Interference", "difficulty": "hard", "style": "standard", "paper": "G11-P3", "q": "Which best describes 'destructive interference' between two waves?", "options": ["the waves combine to produce a larger resultant wave", "the waves combine out of phase, partially or fully cancelling each other out", "destructive interference can only occur with light waves", "two waves can never interfere with each other"], "answer": 1, "exp": "Destructive interference occurs when two waves combine out of phase (a crest meeting a trough), causing them to partially or fully cancel each other out.", "hint": "Think about a peak from one wave lining up with a trough from another, cancelling rather than adding."}, {"id": "srp113019", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Electromagnetic Spectrum", "difficulty": "hard", "style": "standard", "paper": "G11-P3", "q": "Which of the electromagnetic spectrum's waves has the longest wavelength?", "options": ["gamma rays", "visible light", "X-rays", "radio waves"], "answer": 3, "exp": "Radio waves have the longest wavelength (and lowest frequency) of the electromagnetic spectrum, compared to visible light, X-rays, and gamma rays.", "hint": "Think about the type of wave used for long-distance broadcasting, which requires very long wavelengths."}, {"id": "srp113020", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Electromagnetic Spectrum", "difficulty": "hard", "style": "standard", "paper": "G11-P3", "q": "Which of the electromagnetic spectrum's waves has the highest frequency and most energy?", "options": ["radio waves", "microwaves", "visible light", "gamma rays"], "answer": 3, "exp": "Gamma rays have the highest frequency and carry the most energy of the electromagnetic spectrum, which is why they require careful shielding due to their potential to cause biological harm.", "hint": "Think about the type of radiation associated with nuclear processes, known for being highly energetic."}, {"id": "srp113021", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Electromagnetic Spectrum", "difficulty": "hard", "style": "standard", "paper": "G11-P3", "q": "All electromagnetic waves travel at the same speed in a vacuum. What is this speed, approximately?", "options": ["3 × 10⁵ m/s", "3 × 10⁶ m/s", "3 × 10⁷ m/s", "3 × 10⁸ m/s"], "answer": 3, "exp": "All electromagnetic waves travel at the speed of light in a vacuum, approximately 3 × 10⁸ m/s.", "hint": "This is the well-known speed of light constant, often represented by the letter 'c'."}, {"id": "srp113022", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Waves — Light", "difficulty": "hard", "style": "standard", "paper": "G11-P3", "q": "Which best describes why a prism separates white light into a spectrum of colours?", "options": ["the prism adds colour to the light", "different wavelengths of light refract by slightly different amounts as they pass through the glass", "white light contains no colour information at all", "prisms only work with already-coloured light"], "answer": 1, "exp": "Different wavelengths (colours) of light refract by slightly different amounts as they pass through the glass prism, causing them to separate into a visible spectrum.", "hint": "Think about why each colour bends by a slightly different amount as it changes speed entering the glass."}, {"id": "srp113023", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Sound", "difficulty": "hard", "style": "standard", "paper": "G11-P3", "q": "Two sound waves are described: Wave A has a frequency of 200 Hz, Wave B has a frequency of 800 Hz. Which wave has the higher pitch?", "options": ["Wave A", "Wave B", "both have identical pitch", "pitch cannot be determined from frequency alone"], "answer": 1, "exp": "Wave B, with the higher frequency (800 Hz vs 200 Hz), will be perceived as having a higher pitch.", "hint": "Higher frequency corresponds to higher pitch."}, {"id": "srp113024", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Sound", "difficulty": "hard", "style": "standard", "paper": "G11-P3", "q": "Which best describes why sound generally travels faster through solids than through air?", "options": ["solids contain no particles at all", "particles in a solid are packed closely together, allowing vibrations to transfer between them more quickly than in the more widely spaced particles of a gas", "sound cannot actually travel through solids", "air always conducts sound faster than solids"], "answer": 1, "exp": "Particles in a solid are packed closely together, allowing vibrations to transfer between them more quickly than the more widely spaced particles of a gas like air.", "hint": "Think about how closely packed particles are in a solid, compared to a gas."}, {"id": "srp113025", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Waves", "difficulty": "hard", "style": "standard", "paper": "G11-P3", "q": "A wave travels at 6 m/s with a frequency of 3 Hz. Using v = fλ, what is its wavelength?", "options": ["0.5 m", "2 m", "3 m", "18 m"], "answer": 1, "exp": "Step 1: λ = v/f. Step 2: 6 ÷ 3 = 2 m.", "hint": "Rearrange v = fλ to solve for wavelength."}, {"id": "srp114001", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Electricity — Ohm's Law", "difficulty": "hard", "style": "standard", "paper": "G11-P4", "q": "A circuit has a current of 2 A flowing through a 5 Ω resistor. Using V = IR, what is the voltage across the resistor?", "options": ["2.5 V", "7 V", "10 V", "25 V"], "answer": 2, "exp": "Step 1: V = IR. Step 2: 2 × 5 = 10 V.", "hint": "Multiply the current by the resistance."}, {"id": "srp114002", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Electricity — Ohm's Law", "difficulty": "hard", "style": "standard", "paper": "G11-P4", "q": "A 4 Ω resistor has 12 V across it. Using I = V/R, what current flows through it?", "options": ["0.3 A", "3 A", "16 A", "48 A"], "answer": 1, "exp": "Step 1: I = V/R. Step 2: 12 ÷ 4 = 3 A.", "hint": "Divide the voltage by the resistance."}, {"id": "srp114003", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Electricity — Ohm's Law", "difficulty": "hard", "style": "standard", "paper": "G11-P4", "q": "A component has 12 V across it and 3 A flowing through it. Using R = V/I, what is its resistance?", "options": ["4 Ω", "9 Ω", "15 Ω", "36 Ω"], "answer": 0, "exp": "Step 1: R = V/I. Step 2: 12 ÷ 3 = 4 Ω.", "hint": "Divide the voltage by the current."}, {"id": "srp114004", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Electricity — Circuits", "difficulty": "hard", "style": "standard", "paper": "G11-P4", "q": "Three resistors of 4 Ω, 6 Ω, and 10 Ω are connected in series. What is the total resistance?", "options": ["4 Ω", "6 Ω", "10 Ω", "20 Ω"], "answer": 3, "exp": "In a series circuit, total resistance is simply the sum of all resistances: 4 + 6 + 10 = 20 Ω.", "hint": "For resistors in series, simply add up all the individual resistances."}, {"id": "srp114005", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Electricity — Circuits", "difficulty": "hard", "style": "standard", "paper": "G11-P4", "q": "Two resistors, 6 Ω and 3 Ω, are connected in parallel. Using 1/Rtotal = 1/R₁ + 1/R₂, what is the total resistance?", "options": ["1.5 Ω", "2 Ω", "4.5 Ω", "9 Ω"], "answer": 1, "exp": "Step 1: 1/Rtotal = 1/6 + 1/3 = 1/6 + 2/6 = 3/6 = 1/2. Step 2: Rtotal = 2 Ω.", "hint": "Add the reciprocals of each resistance, then take the reciprocal of the result."}, {"id": "srp114006", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Electricity — Circuits", "difficulty": "hard", "style": "standard", "paper": "G11-P4", "q": "In a series circuit, how does the current compare at different points around the circuit?", "options": ["current is always the same at every point in a series circuit", "current increases as it passes through each component", "current decreases as it passes through each component", "current cannot be measured in a series circuit"], "answer": 0, "exp": "In a series circuit, the same current flows through every component, since there is only one path for the current to follow.", "hint": "Think about how many paths the current has to follow in a series circuit."}, {"id": "srp114007", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Electricity — Circuits", "difficulty": "hard", "style": "standard", "paper": "G11-P4", "q": "In a parallel circuit, how does the voltage compare across each parallel branch?", "options": ["voltage is always the same across each parallel branch", "voltage always increases across each successive branch", "voltage is always zero in a parallel circuit", "voltage cannot be measured in a parallel circuit"], "answer": 0, "exp": "In a parallel circuit, each branch has the same voltage across it, since each branch connects directly across the same two points in the circuit.", "hint": "Think about how each parallel branch connects to the same two points in the circuit."}, {"id": "srp114008", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Electricity — Power", "difficulty": "hard", "style": "standard", "paper": "G11-P4", "q": "A circuit has a voltage of 12 V and a current of 2 A. Using P = VI, what is the power?", "options": ["6 W", "10 W", "14 W", "24 W"], "answer": 3, "exp": "Step 1: P = VI. Step 2: 12 × 2 = 24 W.", "hint": "Multiply the voltage by the current."}, {"id": "srp114009", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Electricity — Power", "difficulty": "hard", "style": "standard", "paper": "G11-P4", "q": "A circuit has a current of 2 A flowing through a 5 Ω resistor. Using P = I²R, what power is dissipated?", "options": ["7 W", "10 W", "20 W", "50 W"], "answer": 2, "exp": "Step 1: P = I²R. Step 2: 2² × 5 = 4 × 5 = 20 W.", "hint": "Square the current, then multiply by the resistance."}, {"id": "srp114010", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Electricity — Power", "difficulty": "hard", "style": "standard", "paper": "G11-P4", "q": "A component has 12 V across it and a resistance of 4 Ω. Using P = V²/R, what power is dissipated?", "options": ["3 W", "16 W", "36 W", "48 W"], "answer": 2, "exp": "Step 1: P = V²/R. Step 2: 12² ÷ 4 = 144 ÷ 4 = 36 W.", "hint": "Square the voltage, then divide by the resistance."}, {"id": "srp114011", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Electricity — Energy", "difficulty": "hard", "style": "standard", "paper": "G11-P4", "q": "A heater uses 100 W of power for exactly 1 hour (3600 seconds). Using E = Pt, how much energy does it use, in joules?", "options": ["3,600 J", "36,000 J", "100,000 J", "360,000 J"], "answer": 3, "exp": "Step 1: E = Pt. Step 2: 100 × 3600 = 360,000 J.", "hint": "Multiply the power by the time, making sure the time is in seconds."}, {"id": "srp114012", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Electricity — Charge", "difficulty": "hard", "style": "standard", "paper": "G11-P4", "q": "A current of 2 A flows for 10 seconds. Using Q = It, how much electric charge passes?", "options": ["0.2 C", "5 C", "12 C", "20 C"], "answer": 3, "exp": "Step 1: Q = It. Step 2: 2 × 10 = 20 C.", "hint": "Multiply the current by the time."}, {"id": "srp114013", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Electricity — Energy Costs", "difficulty": "hard", "style": "standard", "paper": "G11-P4", "q": "A 2000 W appliance runs for 3 hours. At a rate of $0.30 per kWh, what is the cost of running it?", "options": ["$0.60", "$1.80", "$6.00", "$18.00"], "answer": 1, "exp": "Step 1: Convert power to kW: 2000 W = 2 kW. Step 2: Energy = power × time = 2 × 3 = 6 kWh. Step 3: Cost = 6 × $0.30 = $1.80.", "hint": "Convert watts to kilowatts first, then multiply by hours and the cost rate."}, {"id": "srp114014", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Electricity — Concepts", "difficulty": "hard", "style": "standard", "paper": "G11-P4", "q": "Which best describes the difference between conductors and insulators?", "options": ["conductors allow electric current to flow easily, while insulators strongly resist current flow", "conductors and insulators behave identically", "insulators always conduct electricity better than conductors", "conductors only work with direct current (DC), never alternating current (AC)"], "answer": 0, "exp": "Conductors (such as most metals) allow electric current to flow easily, due to free-moving electrons, while insulators (such as rubber or plastic) strongly resist the flow of current.", "hint": "Think about materials commonly used for electrical wires versus their protective coatings."}, {"id": "srp114015", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Electricity — Concepts", "difficulty": "hard", "style": "standard", "paper": "G11-P4", "q": "Which best describes electric current?", "options": ["the rate of flow of electric charge", "a measure of resistance in a circuit", "the energy stored in a battery", "a unit used only to measure voltage"], "answer": 0, "exp": "Electric current is the rate of flow of electric charge through a conductor, measured in amperes (A).", "hint": "Think about charge moving through a circuit, and how quickly it moves."}, {"id": "srp114016", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Electricity — Concepts", "difficulty": "hard", "style": "standard", "paper": "G11-P4", "q": "Which best describes voltage (potential difference)?", "options": ["the rate of flow of charge", "the energy transferred per unit of charge between two points in a circuit", "a measure of a material's resistance only", "a unit used only to measure current"], "answer": 1, "exp": "Voltage (potential difference) is the energy transferred per unit of charge between two points in a circuit, measured in volts (V).", "hint": "Think about the 'push' that drives charge around a circuit, related to energy transferred per unit charge."}, {"id": "srp114017", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Electricity — Units", "difficulty": "hard", "style": "standard", "paper": "G11-P4", "q": "What is the SI unit for electrical resistance?", "options": ["ampere (A)", "volt (V)", "ohm (Ω)", "watt (W)"], "answer": 2, "exp": "Electrical resistance is measured in ohms (Ω).", "hint": "This unit's symbol is the Greek letter omega."}, {"id": "srp114018", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Electricity — Circuits", "difficulty": "hard", "style": "standard", "paper": "G11-P4", "q": "Why does adding more resistors in series increase the total resistance of a circuit?", "options": ["each additional resistor provides another obstacle the current must pass through, adding to the total resistance", "series resistors actually decrease total resistance", "resistance is unrelated to the number of components in series", "adding resistors in series has no effect on resistance"], "answer": 0, "exp": "Each additional resistor in series provides another obstacle the current must pass through, and since there's only one path, these resistances simply add together, increasing the total.", "hint": "Think about current having to pass through every single resistor, one after another, in a series circuit."}, {"id": "srp114019", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Electricity — Circuits", "difficulty": "hard", "style": "standard", "paper": "G11-P4", "q": "Why does adding more resistors in parallel decrease the total resistance of a circuit?", "options": ["parallel resistors provide additional paths for current to flow, making it easier overall for current to flow, which reduces total resistance", "parallel resistors always increase total resistance", "parallel circuits have no defined total resistance", "adding resistors in parallel has no effect on total resistance"], "answer": 0, "exp": "Adding resistors in parallel provides additional paths for current to flow, making it easier overall for current to flow through the combined network, which decreases the total resistance.", "hint": "Think about current having multiple alternative paths to choose from in a parallel circuit."}, {"id": "srp114020", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Electricity — Power", "difficulty": "hard", "style": "standard", "paper": "G11-P4", "q": "A globe rated at 60 W operates on a 240 V supply. Using I = P/V, what current does it draw?", "options": ["0.25 A", "0.5 A", "4 A", "14,400 A"], "answer": 0, "exp": "Step 1: Rearranged from P = VI, I = P/V. Step 2: 60 ÷ 240 = 0.25 A.", "hint": "Rearrange P = VI to solve for current."}, {"id": "srp114021", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Electricity — Safety", "difficulty": "hard", "style": "standard", "paper": "G11-P4", "q": "Which best describes what a fuse does in an electrical circuit?", "options": ["it increases the voltage supplied to the circuit", "it melts and breaks the circuit if current exceeds a safe level, protecting the circuit from damage", "it stores electrical energy for later use", "it has no real safety function"], "answer": 1, "exp": "A fuse contains a thin wire that melts and breaks the circuit if current exceeds a safe level, protecting the circuit and connected appliances from damage due to excessive current.", "hint": "Think about a safety device designed to 'break' deliberately under dangerous conditions."}, {"id": "srp114022", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Electricity — Concepts", "difficulty": "hard", "style": "standard", "paper": "G11-P4", "q": "Which best describes alternating current (AC) compared to direct current (DC)?", "options": ["AC flows in only one constant direction, while DC regularly reverses direction", "DC flows in only one constant direction, while AC regularly reverses direction", "AC and DC are exactly the same thing", "DC is used exclusively in household power supplies worldwide"], "answer": 1, "exp": "Direct current (DC) flows in only one constant direction, while alternating current (AC) regularly reverses direction — household mains power is typically supplied as AC.", "hint": "Think about which type of current is supplied to most homes, and how it differs from a battery's output."}, {"id": "srp114023", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Electricity — Circuits", "difficulty": "hard", "style": "standard", "paper": "G11-P4", "q": "A series circuit contains a 6 V battery and two identical resistors. If the voltage across one resistor is 3 V, what is the voltage across the other resistor?", "options": ["1.5 V", "3 V", "6 V", "9 V"], "answer": 1, "exp": "In a series circuit, the total voltage supplied by the battery is shared among the components: 6 V total − 3 V (first resistor) = 3 V for the second resistor.", "hint": "Remember that voltages in a series circuit must add up to the total supply voltage."}, {"id": "srp114024", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Electricity — Concepts", "difficulty": "hard", "style": "standard", "paper": "G11-P4", "q": "Which best describes why birds can safely perch on a single high-voltage power line without being electrocuted?", "options": ["birds are naturally immune to electricity", "since both of the bird's feet touch the same wire at the same potential, there is no significant voltage difference across the bird's body for current to flow through", "power lines carry no actual electrical current", "birds are too light to conduct electricity"], "answer": 1, "exp": "Since both of the bird's feet touch the same wire (at the same electrical potential), there is no significant voltage difference across its body, so current has no strong reason to flow through the bird rather than continuing along the wire.", "hint": "Think about whether there's a meaningful difference in electrical potential between the bird's two feet."}, {"id": "srp114025", "state": "AU", "section": "sr_physics", "grade": "11", "topic": "Electricity — Ohm's Law", "difficulty": "hard", "style": "standard", "paper": "G11-P4", "q": "A circuit has a total resistance of 10 Ω and a current of 0.5 A. Using V = IR, what is the supply voltage?", "options": ["2 V", "5 V", "10 V", "20 V"], "answer": 1, "exp": "Step 1: V = IR. Step 2: 0.5 × 10 = 5 V.", "hint": "Multiply the current by the total resistance."}, {"id": "srp121001", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Electromagnetism", "difficulty": "hard", "style": "standard", "paper": "G12-P1", "q": "What is 'electromagnetic induction'?", "options": ["the process of a magnet attracting iron filings", "the generation of an electric current in a conductor due to a changing magnetic field", "the process of converting light into electricity directly", "a type of nuclear reaction"], "answer": 1, "exp": "Electromagnetic induction is the generation of an electric current (or EMF) in a conductor due to a changing magnetic field around it, the principle behind generators and transformers.", "hint": "Think about what happens in a conductor when a magnetic field around it changes."}, {"id": "srp121002", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Electromagnetism", "difficulty": "hard", "style": "standard", "paper": "G12-P1", "q": "Which best describes Faraday's law of electromagnetic induction?", "options": ["the induced EMF in a circuit is proportional to the rate of change of magnetic flux through it", "current always flows in the same direction regardless of magnetic field changes", "magnetic fields have no effect on electrical conductors", "induced EMF only occurs in permanent magnets"], "answer": 0, "exp": "Faraday's law states that the induced EMF (voltage) in a circuit is proportional to the rate of change of magnetic flux passing through it — the faster the flux changes, the greater the induced EMF.", "hint": "Think about the relationship between how QUICKLY a magnetic field changes, and how much voltage is induced."}, {"id": "srp121003", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Electromagnetism", "difficulty": "hard", "style": "standard", "paper": "G12-P1", "q": "Which best describes Lenz's law?", "options": ["induced current always flows in a direction that reinforces the change in magnetic flux that caused it", "an induced current always flows in a direction that opposes the change in magnetic flux that caused it", "Lenz's law applies only to direct current circuits", "induced current has no defined direction"], "answer": 1, "exp": "Lenz's law states that an induced current always flows in a direction that opposes the change in magnetic flux that caused it, consistent with the law of conservation of energy.", "hint": "Think about why an induced effect would naturally oppose, rather than reinforce, its own cause."}, {"id": "srp121004", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Electromagnetism — Transformers", "difficulty": "hard", "style": "standard", "paper": "G12-P1", "q": "A step-down transformer has 1000 turns on its primary coil and 100 turns on its secondary coil. If the primary voltage is 240 V, using Vp/Vs = Np/Ns, what is the secondary voltage?", "options": ["2.4 V", "24 V", "240 V", "2400 V"], "answer": 1, "exp": "Step 1: Vp/Vs = Np/Ns, so Vs = Vp × (Ns/Np). Step 2: Vs = 240 × (100/1000) = 24 V.", "hint": "Rearrange the transformer equation to solve for the secondary voltage."}, {"id": "srp121005", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Electromagnetism — Transformers", "difficulty": "hard", "style": "standard", "paper": "G12-P1", "q": "For the same transformer (1000 primary turns, 100 secondary turns), if the primary current is 2 A, using Ip×Np = Is×Ns, what is the secondary current?", "options": ["0.2 A", "2 A", "20 A", "200 A"], "answer": 2, "exp": "Step 1: Ip × Np = Is × Ns, so Is = Ip × (Np/Ns). Step 2: Is = 2 × (1000/100) = 20 A.", "hint": "Rearrange the transformer current equation to solve for the secondary current."}, {"id": "srp121006", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Electromagnetism — Transformers", "difficulty": "hard", "style": "standard", "paper": "G12-P1", "q": "Which best describes the purpose of a step-up transformer in long-distance electricity transmission?", "options": ["to increase voltage and decrease current, reducing energy losses due to resistance in transmission lines", "to decrease voltage for safer use in homes", "step-up transformers serve no practical purpose in power transmission", "to convert AC to DC for transmission"], "answer": 0, "exp": "A step-up transformer increases voltage (while decreasing current for the same power) before long-distance transmission, which reduces energy losses due to resistance, since power loss depends on current squared.", "hint": "Think about why lower current (even with higher voltage) reduces energy lost as heat in transmission lines."}, {"id": "srp121007", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Electromagnetism", "difficulty": "hard", "style": "standard", "paper": "G12-P1", "q": "What is the direction of the force on a current-carrying conductor placed in a magnetic field, according to the right-hand slap rule (or F = qv × B principle)?", "options": ["always parallel to the current's direction", "perpendicular to both the current direction and the magnetic field direction", "always parallel to the magnetic field", "there is no defined direction for this force"], "answer": 1, "exp": "The force on a current-carrying conductor in a magnetic field acts perpendicular to both the current's direction and the magnetic field's direction, as described by the right-hand slap rule (or motor effect).", "hint": "Think about the three-dimensional relationship between current, field, and the resulting force, all at right angles to each other."}, {"id": "srp121008", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Electromagnetism — Generators", "difficulty": "hard", "style": "standard", "paper": "G12-P1", "q": "Which best describes the basic operating principle of an electric generator?", "options": ["it converts electrical energy into mechanical energy", "it converts mechanical energy (rotation) into electrical energy via electromagnetic induction", "it stores electrical charge for later use", "it converts chemical energy directly into light energy"], "answer": 1, "exp": "An electric generator converts mechanical energy (such as rotational motion) into electrical energy, using electromagnetic induction as a coil rotates within a magnetic field.", "hint": "Think about the reverse process of an electric motor — using motion to create electricity, rather than electricity to create motion."}, {"id": "srp121009", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Electromagnetism — Motors", "difficulty": "hard", "style": "standard", "paper": "G12-P1", "q": "Which best describes the basic operating principle of an electric motor?", "options": ["it converts electrical energy into mechanical energy (motion), using the force on a current-carrying conductor in a magnetic field", "it converts mechanical energy into electrical energy", "it only works with alternating current", "it has no connection to magnetic fields"], "answer": 0, "exp": "An electric motor converts electrical energy into mechanical energy (motion), using the force exerted on a current-carrying conductor placed within a magnetic field.", "hint": "Think about the reverse process of a generator — using electricity to create motion."}, {"id": "srp121010", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Electromagnetism", "difficulty": "hard", "style": "standard", "paper": "G12-P1", "q": "Why does pushing a magnet into a coil of wire faster induce a greater EMF than pushing it in slowly?", "options": ["induced EMF is unrelated to the speed of magnetic field change", "a faster change increases the rate of change of magnetic flux, which directly increases the induced EMF, according to Faraday's law", "faster motion always decreases magnetic flux", "induced EMF only depends on the magnet's strength, not its speed"], "answer": 1, "exp": "According to Faraday's law, induced EMF is proportional to the RATE of change of magnetic flux. Moving the magnet faster increases this rate of change, directly increasing the induced EMF.", "hint": "Think about Faraday's law specifically relating EMF to how QUICKLY flux changes, not just how much it changes overall."}, {"id": "srp121011", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Electromagnetism", "difficulty": "hard", "style": "standard", "paper": "G12-P1", "q": "Which best describes 'magnetic flux'?", "options": ["the total electric charge passing through a circuit", "a measure of the total magnetic field passing through a given area", "a unit used to measure electrical resistance", "a term with no defined physical meaning"], "answer": 1, "exp": "Magnetic flux is a measure of the total magnetic field passing through a given area, taking into account the field's strength and the angle at which it passes through that area.", "hint": "Think about the total 'amount' of magnetic field passing through a particular surface."}, {"id": "srp121012", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Electromagnetism — Transformers", "difficulty": "hard", "style": "standard", "paper": "G12-P1", "q": "A transformer is described as having an efficiency of less than 100% in practice. What is the main reason for this?", "options": ["transformers are always perfectly efficient with no energy loss", "some energy is lost as heat due to resistance in the coils and other factors like eddy currents", "transformers actually create extra energy", "efficiency calculations do not apply to transformers"], "answer": 1, "exp": "In practice, some energy is lost as heat due to resistance in the transformer's coils, as well as other factors such as eddy currents in the core, preventing transformers from being perfectly (100%) efficient.", "hint": "Think about where some of the input energy 'leaks away' to, rather than being fully transferred to the output."}, {"id": "srp121013", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Electromagnetism — Transformers", "difficulty": "hard", "style": "standard", "paper": "G12-P1", "q": "Which best describes why AC (alternating current) is generally preferred over DC for long-distance power transmission?", "options": ["AC cannot be transformed to different voltages, unlike DC", "AC can be easily transformed to high voltages for transmission (reducing losses) and back down to safer voltages for use, using transformers", "DC always travels faster than AC over long distances", "there is no practical difference between AC and DC for transmission"], "answer": 1, "exp": "AC can be easily transformed to high voltages (reducing transmission losses) and then back down to safer voltages for household use, using transformers — a much more difficult process with DC.", "hint": "Think about why the ability to easily change voltage levels matters for efficient long-distance transmission."}, {"id": "srp121014", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Electromagnetism — Generators", "difficulty": "hard", "style": "standard", "paper": "G12-P1", "q": "A generator coil rotates within a magnetic field. At which point in its rotation is the induced EMF at its maximum?", "options": ["when the coil is parallel to the magnetic field, cutting through the most field lines per unit time", "when the coil is perpendicular to the magnetic field, cutting through no field lines", "EMF remains constant throughout the entire rotation", "induced EMF is unrelated to the coil's orientation"], "answer": 0, "exp": "The induced EMF is at its maximum when the coil is moving parallel to the magnetic field lines, since this is when the rate of change of magnetic flux through the coil is greatest.", "hint": "Think about the orientation where the coil is cutting through the most field lines per unit of time, not the least."}, {"id": "srp121015", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Electromagnetism", "difficulty": "hard", "style": "standard", "paper": "G12-P1", "q": "Which best describes the right-hand grip rule, used to determine the direction of a magnetic field around a current-carrying wire?", "options": ["pointing the thumb in the direction of conventional current flow, the curled fingers indicate the direction of the surrounding magnetic field", "pointing the thumb in the direction of the magnetic field, the fingers indicate current direction", "this rule only applies to permanent magnets, not current-carrying wires", "there is no reliable way to determine magnetic field direction around a wire"], "answer": 0, "exp": "Using the right-hand grip rule, pointing the thumb in the direction of conventional current flow, the curled fingers indicate the direction of the magnetic field circling around the wire.", "hint": "Think about gripping the wire with your right hand, thumb pointing along the current's direction."}, {"id": "srp121016", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Electromagnetism — Transformers", "difficulty": "hard", "style": "standard", "paper": "G12-P1", "q": "Which best describes why a transformer cannot be used to step up or step down a direct current (DC) voltage?", "options": ["DC voltage can be transformed exactly the same way as AC", "transformers rely on a continuously changing magnetic flux (from alternating current) to induce a voltage in the secondary coil — a steady DC current produces no changing flux", "transformers have no connection to magnetic flux at all", "DC current is always too weak for any transformer to use"], "answer": 1, "exp": "Transformers rely on a continuously changing magnetic flux, produced by alternating current, to induce a voltage in the secondary coil. A steady DC current produces a constant magnetic field with no change in flux, so no EMF is induced.", "hint": "Think about what Faraday's law requires — a CHANGING flux — and whether steady DC current can provide that."}, {"id": "srp121017", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Electromagnetism — Power Transmission", "difficulty": "hard", "style": "standard", "paper": "G12-P1", "q": "A power station transmits 100,000 W of power at 10,000 V. Using P = VI, what current flows through the transmission line?", "options": ["1 A", "10 A", "100 A", "1000 A"], "answer": 1, "exp": "Step 1: P = VI, so I = P/V. Step 2: I = 100,000 ÷ 10,000 = 10 A.", "hint": "Rearrange P = VI to solve for current."}, {"id": "srp121018", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Electromagnetism — Power Transmission", "difficulty": "hard", "style": "standard", "paper": "G12-P1", "q": "Which best describes why increasing transmission voltage reduces power loss in transmission lines, given the same power being delivered?", "options": ["higher voltage requires lower current for the same power, and power loss due to resistance depends on current squared (P = I²R), so lower current significantly reduces losses", "higher voltage always increases current, increasing losses", "voltage has no relationship to power loss in transmission lines", "power loss depends only on the length of the wire, not voltage or current"], "answer": 0, "exp": "For the same power delivered, higher voltage means lower current is needed (since P=VI). Since power loss due to resistance depends on current squared (P=I²R), reducing current significantly reduces these losses.", "hint": "Think about the relationship P=VI (to keep power constant) combined with P=I²R (for power lost to resistance)."}, {"id": "srp121019", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Electromagnetism — Transformers", "difficulty": "hard", "style": "standard", "paper": "G12-P1", "q": "Which best describes an 'eddy current' within a transformer's iron core?", "options": ["a deliberate current used to power the transformer", "an unwanted, induced circulating current within the core itself, caused by the changing magnetic field, which generates wasteful heat", "a current that only flows through the primary coil", "a type of current that increases a transformer's efficiency"], "answer": 1, "exp": "An eddy current is an unwanted, induced circulating current within the transformer's iron core itself, caused by the changing magnetic field, which generates wasteful heat and reduces efficiency.", "hint": "Think about an unwanted current induced directly within the solid metal core, rather than in the coils."}, {"id": "srp121020", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Electromagnetism — Transformers", "difficulty": "hard", "style": "standard", "paper": "G12-P1", "q": "Why are transformer cores often made of laminated (thin, layered) iron sheets rather than a single solid block?", "options": ["lamination has no real benefit and is purely a manufacturing convenience", "laminating the core into thin, insulated layers reduces eddy currents, improving efficiency", "laminated cores are always heavier than solid ones", "lamination increases the core's magnetic field strength"], "answer": 1, "exp": "Laminating the core into thin, insulated layers restricts the paths available for eddy currents to circulate, significantly reducing their size and the wasteful heat they generate, improving overall efficiency.", "hint": "Think about how breaking up the solid metal core into thin, separated layers might limit unwanted circulating currents."}, {"id": "srp121021", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Electromagnetism", "difficulty": "hard", "style": "standard", "paper": "G12-P1", "q": "Which best describes the relationship between electricity and magnetism, as unified by electromagnetic theory?", "options": ["electricity and magnetism are completely unrelated phenomena", "a changing electric field can produce a magnetic field, and a changing magnetic field can produce an electric field — they are deeply interconnected", "magnetism can exist without any connection to electric charge or current", "electric fields can never influence magnetic fields"], "answer": 1, "exp": "Electromagnetic theory shows that electricity and magnetism are deeply interconnected: a changing electric field can produce a magnetic field, and a changing magnetic field can produce an electric field (or induced current).", "hint": "Think about how changing one of these fields can directly create the other — they aren't independent phenomena."}, {"id": "srp121022", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Electromagnetism — Transformers", "difficulty": "hard", "style": "standard", "paper": "G12-P1", "q": "A step-up transformer increases voltage from 240 V to 24,000 V. What is the turns ratio (secondary:primary)?", "options": ["1:10", "1:100", "10:1", "100:1"], "answer": 3, "exp": "Step 1: Vs/Vp = Ns/Np. Step 2: 24,000 ÷ 240 = 100, so the secondary coil has 100 times more turns than the primary, giving a ratio of 100:1 (secondary:primary).", "hint": "Divide the secondary voltage by the primary voltage to find the turns ratio."}, {"id": "srp121023", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Electromagnetism — Motors", "difficulty": "hard", "style": "standard", "paper": "G12-P1", "q": "Which best describes the term 'back EMF' in an electric motor?", "options": ["an EMF induced in the motor's coil (as it rotates in the magnetic field) that opposes the applied voltage driving the motor", "an EMF that has no real effect on motor operation", "a type of EMF that only occurs when a motor is switched off", "an EMF generated exclusively by the motor's power supply"], "answer": 0, "exp": "As a motor's coil rotates within a magnetic field, it itself acts like a generator, inducing a 'back EMF' that opposes the applied voltage driving the motor, in accordance with Lenz's law.", "hint": "Think about the motor's own rotation inducing an opposing EMF, due to the same principles that make a generator work."}, {"id": "srp121024", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Electromagnetism — Motors", "difficulty": "hard", "style": "standard", "paper": "G12-P1", "q": "Which best explains why an induction motor can run without any direct electrical connection to its rotor?", "options": ["induction motors cannot actually run without a direct electrical connection", "a changing magnetic field from the stator induces a current directly in the rotor, which then experiences a force, causing rotation", "induction motors do not use magnetic fields at all", "the rotor is connected wirelessly via radio signals"], "answer": 1, "exp": "In an induction motor, a changing magnetic field produced by the stator induces a current directly in the rotor (via electromagnetic induction), and this induced current then experiences a force within the magnetic field, causing the rotor to turn.", "hint": "Think about electromagnetic induction creating current in the rotor itself, without needing a direct wired connection."}, {"id": "srp121025", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Electromagnetism", "difficulty": "hard", "style": "standard", "paper": "G12-P1", "q": "A generator coil with 50 turns experiences a rate of change of magnetic flux of 0.2 Wb/s through each turn. Using EMF = N × (rate of change of flux), what is the induced EMF?", "options": ["0.25 V", "2.5 V", "10 V", "250 V"], "answer": 2, "exp": "Step 1: EMF = N × (rate of change of flux). Step 2: 50 × 0.2 = 10 V.", "hint": "Multiply the number of turns by the rate of change of magnetic flux per turn."}, {"id": "srp122001", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Quantum Physics", "difficulty": "hard", "style": "standard", "paper": "G12-P2", "q": "Using E = hf, what is the energy of a photon with frequency 6 × 10¹⁴ Hz? (h ≈ 6.63 × 10⁻³⁴ J·s)", "options": ["3.98 × 10⁻²⁰ J", "3.98 × 10⁻¹⁹ J", "3.98 × 10⁻¹⁸ J", "3.98 × 10¹⁹ J"], "answer": 1, "exp": "Step 1: E = hf. Step 2: 6.63×10⁻³⁴ × 6×10¹⁴ = 3.978×10⁻¹⁹ J.", "hint": "Multiply Planck's constant by the frequency, keeping careful track of the powers of 10."}, {"id": "srp122002", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Quantum Physics", "difficulty": "hard", "style": "standard", "paper": "G12-P2", "q": "Which best describes the photoelectric effect?", "options": ["light bending as it passes through glass", "the emission of electrons from a material's surface when light of sufficient frequency shines on it", "the splitting of white light into a spectrum of colours", "the reflection of light off a mirror"], "answer": 1, "exp": "The photoelectric effect is the emission of electrons from a material's surface when light of sufficient frequency (above a threshold) shines on it.", "hint": "Think about light causing electrons to be released from a surface, rather than simply reflecting or refracting."}, {"id": "srp122003", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Quantum Physics", "difficulty": "hard", "style": "standard", "paper": "G12-P2", "q": "Which best explains why the photoelectric effect could not be fully explained by classical wave theory of light?", "options": ["classical theory predicted electron emission would depend only on light intensity, regardless of frequency — but experiments showed a minimum threshold frequency was required, regardless of intensity", "classical wave theory perfectly explains all aspects of the photoelectric effect", "the photoelectric effect has nothing to do with light at all", "classical theory predicted no electrons would ever be emitted"], "answer": 0, "exp": "Classical wave theory predicted that electron emission should depend on light intensity, regardless of frequency. However, experiments showed a minimum threshold frequency was required, below which no electrons were emitted no matter how intense the light — only explained by treating light as discrete photons (quanta).", "hint": "Think about the surprising experimental finding that intensity alone wasn't enough — frequency mattered."}, {"id": "srp122004", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Quantum Physics", "difficulty": "hard", "style": "standard", "paper": "G12-P2", "q": "Which best describes a 'photon'?", "options": ["a discrete packet (quantum) of electromagnetic energy", "a type of subatomic particle found only in atomic nuclei", "a unit used to measure electric current", "a wave with no defined energy"], "answer": 0, "exp": "A photon is a discrete packet (quantum) of electromagnetic energy, with energy related to its frequency by E = hf.", "hint": "Think about light being treated not as a continuous wave, but as individual 'packets' of energy."}, {"id": "srp122005", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Thermodynamics", "difficulty": "hard", "style": "standard", "paper": "G12-P2", "q": "0.5 kg of water is heated, raising its temperature by 20°C. Using Q = mcΔT (with c ≈ 4200 J/kg°C for water), how much heat energy is required?", "options": ["4,200 J", "21,000 J", "42,000 J", "84,000 J"], "answer": 2, "exp": "Step 1: Q = mcΔT. Step 2: 0.5 × 4200 × 20 = 42,000 J.", "hint": "Substitute the mass, specific heat capacity, and temperature change into Q = mcΔT."}, {"id": "srp122006", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Thermodynamics", "difficulty": "hard", "style": "standard", "paper": "G12-P2", "q": "42,000 J of heat raises the temperature of a 2 kg substance by 5°C. Using c = Q/(mΔT), what is its specific heat capacity?", "options": ["420 J/kg°C", "2,100 J/kg°C", "4,200 J/kg°C", "8,400 J/kg°C"], "answer": 2, "exp": "Step 1: c = Q/(mΔT). Step 2: 42,000 ÷ (2×5) = 42,000 ÷ 10 = 4,200 J/kg°C.", "hint": "Rearrange Q = mcΔT to solve for specific heat capacity."}, {"id": "srp122007", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Nuclear Physics", "difficulty": "hard", "style": "standard", "paper": "G12-P2", "q": "A radioactive sample starts with 200 g and undergoes 3 half-lives. How much of the original sample remains?", "options": ["12.5 g", "25 g", "50 g", "75 g"], "answer": 1, "exp": "Step 1: After each half-life, the mass halves: 200 → 100 → 50 → 25. Step 2: After 3 half-lives, 25 g remains.", "hint": "Halve the original amount once for each half-life that has passed."}, {"id": "srp122008", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Nuclear Physics", "difficulty": "hard", "style": "standard", "paper": "G12-P2", "q": "A radioactive sample decreases from 80 g to 10 g. How many half-lives have passed?", "options": ["2", "3", "4", "8"], "answer": 1, "exp": "Step 1: 80 → 40 (1 half-life) → 20 (2 half-lives) → 10 (3 half-lives). Step 2: 3 half-lives have passed.", "hint": "Halve the starting amount repeatedly until you reach the final amount, counting each halving."}, {"id": "srp122009", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Nuclear Physics", "difficulty": "hard", "style": "standard", "paper": "G12-P2", "q": "Which best describes 'half-life' in the context of radioactive decay?", "options": ["the total time for a radioactive sample to completely disappear", "the time required for half of a radioactive sample's original nuclei to decay", "a measure of a sample's total mass", "a unit used to measure radiation exposure"], "answer": 1, "exp": "Half-life is the time required for half of a radioactive sample's original (undecayed) nuclei to decay.", "hint": "Think about the specific time it takes for exactly half of the original material to decay."}, {"id": "srp122010", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Nuclear Physics", "difficulty": "hard", "style": "standard", "paper": "G12-P2", "q": "Which best describes 'alpha decay'?", "options": ["the emission of a high-energy electron from the nucleus", "the emission of a helium nucleus (2 protons, 2 neutrons) from a larger nucleus", "the emission of a photon with no change in nucleus composition", "the splitting of a nucleus into two roughly equal parts"], "answer": 1, "exp": "Alpha decay involves the emission of an alpha particle — a helium nucleus consisting of 2 protons and 2 neutrons — from a larger, unstable nucleus.", "hint": "Think about the specific particle emitted: it's identical to a helium nucleus."}, {"id": "srp122011", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Nuclear Physics", "difficulty": "hard", "style": "standard", "paper": "G12-P2", "q": "Which best describes 'beta decay'?", "options": ["the emission of a helium nucleus", "the emission of a high-energy electron (or positron) as a neutron converts into a proton (or vice versa) within the nucleus", "the emission of a high-energy photon with no particle change", "a process that only occurs in stable nuclei"], "answer": 1, "exp": "Beta decay involves the emission of a high-energy electron (beta particle) as a neutron converts into a proton within the nucleus (or a positron if a proton converts into a neutron).", "hint": "Think about a particle being emitted as one type of nucleon transforms into another within the nucleus."}, {"id": "srp122012", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Nuclear Physics", "difficulty": "hard", "style": "standard", "paper": "G12-P2", "q": "Which best describes 'gamma decay' (gamma emission)?", "options": ["the emission of a high-energy electromagnetic photon from an unstable nucleus, often following alpha or beta decay, with no change in the nucleus's proton or neutron count", "the emission of a helium nucleus", "a process that always occurs alone, never alongside other types of decay", "a process exclusive to extremely large atoms"], "answer": 0, "exp": "Gamma decay involves the emission of a high-energy electromagnetic photon (gamma ray) from an unstable nucleus, often following alpha or beta decay, without changing the nucleus's proton or neutron count.", "hint": "Think about a type of decay that releases pure energy as a photon, rather than emitting a particle with mass."}, {"id": "srp122013", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Modern Physics — Mass-Energy Equivalence", "difficulty": "hard", "style": "standard", "paper": "G12-P2", "q": "Using E = mc² (with c ≈ 3 × 10⁸ m/s), approximately how much energy is equivalent to 0.001 kg of mass?", "options": ["3 × 10¹² J", "9 × 10¹² J", "3 × 10¹³ J", "9 × 10¹³ J"], "answer": 3, "exp": "Step 1: E = mc². Step 2: 0.001 × (3×10⁸)² = 0.001 × 9×10¹⁶ = 9×10¹³ J.", "hint": "Square the speed of light first, then multiply by the mass."}, {"id": "srp122014", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Modern Physics", "difficulty": "hard", "style": "standard", "paper": "G12-P2", "q": "Which best describes the significance of E = mc² in modern physics?", "options": ["it shows that energy and mass are completely unrelated quantities", "it shows that mass and energy are equivalent and can be converted between each other", "it only applies to objects travelling at the speed of light", "it has no real physical significance, being purely theoretical"], "answer": 1, "exp": "E = mc² shows that mass and energy are equivalent and can, in principle, be converted between each other, with even small amounts of mass corresponding to enormous amounts of energy due to the large value of c².", "hint": "Think about what this equation suggests about the relationship between these two seemingly different quantities."}, {"id": "srp122015", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Nuclear Physics", "difficulty": "hard", "style": "standard", "paper": "G12-P2", "q": "Which best describes the process of nuclear fission?", "options": ["the joining of two light nuclei to form a heavier nucleus, releasing energy", "the splitting of a heavy nucleus into two lighter nuclei, releasing energy", "a process that releases no energy at all", "a process that only occurs in stars"], "answer": 1, "exp": "Nuclear fission is the splitting of a heavy nucleus (such as uranium) into two lighter nuclei, releasing a substantial amount of energy in the process, as used in nuclear power stations.", "hint": "Think about a large nucleus being split apart, rather than two smaller ones joining."}, {"id": "srp122016", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Nuclear Physics", "difficulty": "hard", "style": "standard", "paper": "G12-P2", "q": "Which best describes the process of nuclear fusion?", "options": ["the splitting of a heavy nucleus into lighter parts", "the joining of two light nuclei to form a heavier nucleus, releasing energy, as occurs in stars", "a process that absorbs energy rather than releasing it", "a process that only occurs at very low temperatures"], "answer": 1, "exp": "Nuclear fusion is the joining of two light nuclei (such as hydrogen) to form a heavier nucleus, releasing a substantial amount of energy — this is the process that powers the Sun and other stars.", "hint": "Think about two smaller nuclei combining together, releasing energy, rather than a large one splitting apart."}, {"id": "srp122017", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Thermodynamics — Latent Heat", "difficulty": "hard", "style": "standard", "paper": "G12-P2", "q": "2 kg of ice at 0°C is melted completely into water at 0°C. Using Q = mL (with L ≈ 334,000 J/kg for ice), how much energy is required?", "options": ["167,000 J", "334,000 J", "668,000 J", "1,336,000 J"], "answer": 2, "exp": "Step 1: Q = mL. Step 2: 2 × 334,000 = 668,000 J.", "hint": "Multiply the mass by the specific latent heat of fusion."}, {"id": "srp122018", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Thermodynamics — Latent Heat", "difficulty": "hard", "style": "standard", "paper": "G12-P2", "q": "Why does melting ice require energy input, even though its temperature does not change during the process?", "options": ["melting does not actually require any energy", "the energy is used to break the intermolecular bonds holding the solid structure together, rather than to increase kinetic energy (temperature)", "ice is actually getting colder during melting", "this represents a violation of the law of conservation of energy"], "answer": 1, "exp": "During melting, energy input is used to break the intermolecular bonds holding the solid's rigid structure together, rather than increasing the average kinetic energy (and thus temperature) of the particles.", "hint": "Think about where the energy goes if it's not increasing the temperature — into changing the structure itself."}, {"id": "srp122019", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Thermodynamics", "difficulty": "hard", "style": "standard", "paper": "G12-P2", "q": "Which best describes the zeroth law of thermodynamics?", "options": ["energy cannot be created or destroyed", "if two systems are each in thermal equilibrium with a third system, they are also in thermal equilibrium with each other", "entropy of an isolated system always increases over time", "heat always flows from cold to hot objects"], "answer": 1, "exp": "The zeroth law of thermodynamics states that if two systems are each in thermal equilibrium with a third system, they are also in thermal equilibrium with each other — this underlies the concept of temperature itself.", "hint": "Think about a transitive relationship between three systems all reaching the same temperature."}, {"id": "srp122020", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Thermodynamics", "difficulty": "hard", "style": "standard", "paper": "G12-P2", "q": "Which best describes the first law of thermodynamics?", "options": ["energy cannot be created or destroyed, only transferred or transformed between forms", "entropy always decreases in an isolated system", "heat always flows spontaneously from cold to hot objects", "temperature and energy are completely unrelated quantities"], "answer": 0, "exp": "The first law of thermodynamics is essentially the law of conservation of energy: energy cannot be created or destroyed, only transferred between objects or transformed between different forms.", "hint": "Think about this law as a specific application of the broader principle of energy conservation."}, {"id": "srp122021", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Thermodynamics", "difficulty": "hard", "style": "standard", "paper": "G12-P2", "q": "Which best describes the second law of thermodynamics, in terms of entropy?", "options": ["entropy of an isolated system always decreases over time", "the total entropy of an isolated system never decreases over time, tending to increase", "entropy has no real physical meaning", "entropy only applies to living systems"], "answer": 1, "exp": "The second law of thermodynamics states that the total entropy (a measure of disorder) of an isolated system never decreases over time — it tends to increase, or at best remain the same in an idealised, reversible process.", "hint": "Think about the natural tendency of isolated systems to become more disordered over time, not less."}, {"id": "srp122022", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Thermodynamics", "difficulty": "hard", "style": "standard", "paper": "G12-P2", "q": "Which best explains why heat naturally flows from a hotter object to a cooler one, and not the reverse, without external work being done?", "options": ["heat actually flows equally in both directions at all times", "this direction of flow is consistent with the second law of thermodynamics, since it results in increased overall entropy", "heat flow direction is completely random", "cooler objects always contain more total energy than hotter ones"], "answer": 1, "exp": "Heat flowing from hotter to cooler objects results in an overall increase in entropy, consistent with the second law of thermodynamics — heat flowing the other way (without external work) would actually decrease overall entropy, which doesn't happen spontaneously.", "hint": "Think about which direction of heat flow leads to increased disorder (entropy) overall."}, {"id": "srp122023", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Thermodynamics", "difficulty": "hard", "style": "standard", "paper": "G12-P2", "q": "Which best describes 'absolute zero' on the Kelvin temperature scale?", "options": ["the temperature at which water freezes", "the theoretical temperature at which particles have minimum possible kinetic energy, approximately -273.15°C", "the hottest possible temperature in the universe", "a temperature that has been achieved exactly in laboratory conditions"], "answer": 1, "exp": "Absolute zero (0 K, approximately -273.15°C) is the theoretical temperature at which particles have the minimum possible kinetic energy, though it has never been achieved exactly in practice.", "hint": "Think about the lowest theoretically possible temperature, where particle motion is minimised."}, {"id": "srp122024", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Nuclear Physics", "difficulty": "hard", "style": "standard", "paper": "G12-P2", "q": "Which best describes why nuclear power stations use controlled nuclear fission rather than an uncontrolled chain reaction?", "options": ["controlled fission allows energy to be released gradually and safely for electricity generation, rather than all at once", "uncontrolled reactions actually produce more usable electricity", "nuclear power stations do not actually use fission at all", "there is no meaningful difference between controlled and uncontrolled fission"], "answer": 0, "exp": "Controlled nuclear fission allows the energy released by splitting nuclei to be managed gradually and safely, generating steady heat to produce electricity, rather than releasing all the energy uncontrollably and dangerously at once.", "hint": "Think about why a steady, manageable release of energy is preferable to an explosive, uncontrolled one for generating electricity."}, {"id": "srp122025", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Quantum Physics", "difficulty": "hard", "style": "standard", "paper": "G12-P2", "q": "Using E = hf, if a photon has an energy of 4.97 × 10⁻¹⁹ J, what is its approximate frequency? (h ≈ 6.63 × 10⁻³⁴ J·s)", "options": ["3.0 × 10¹⁴ Hz", "5.0 × 10¹⁴ Hz", "7.5 × 10¹⁴ Hz", "9.0 × 10¹⁴ Hz"], "answer": 2, "exp": "Step 1: f = E/h. Step 2: (4.97×10⁻¹⁹) ÷ (6.63×10⁻³⁴) ≈ 7.5×10¹⁴ Hz.", "hint": "Rearrange E = hf to solve for frequency."}, {"id": "srp123001", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Gravitation", "difficulty": "hard", "style": "standard", "paper": "G12-P3", "q": "Using Newton's law of gravitation, Fg = GMm/r², what happens to the gravitational force between two objects if the distance between them doubles?", "options": ["it doubles", "it halves", "it becomes one quarter of the original value", "it remains unchanged"], "answer": 2, "exp": "Since force is inversely proportional to the SQUARE of distance, doubling the distance (r→2r) reduces the force to 1/2² = 1/4 of its original value.", "hint": "Remember that distance is squared in the denominator of this formula — doubling it has a squared effect on the result."}, {"id": "srp123002", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Gravitation", "difficulty": "hard", "style": "standard", "paper": "G12-P3", "q": "Using g = GM/r², approximately what is the gravitational field strength at Earth's surface? (G ≈ 6.67×10⁻¹¹, M ≈ 5.97×10²⁴ kg, r ≈ 6.37×10⁶ m)", "options": ["6.7 m/s²", "8.9 m/s²", "9.8 m/s²", "11.2 m/s²"], "answer": 2, "exp": "Step 1: g = GM/r². Step 2: (6.67×10⁻¹¹ × 5.97×10²⁴) ÷ (6.37×10⁶)² ≈ 9.8 m/s².", "hint": "Substitute the values carefully, paying attention to the powers of 10."}, {"id": "srp123003", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Gravitation", "difficulty": "hard", "style": "standard", "paper": "G12-P3", "q": "Which best describes a 'gravitational field'?", "options": ["a region of space where a mass experiences a gravitational force", "a measure of an object's total mass", "a unit used to measure gravitational potential energy only", "a field that only exists near the Earth"], "answer": 0, "exp": "A gravitational field is a region of space surrounding a mass, within which another mass would experience a gravitational force.", "hint": "Think about the region of influence surrounding any object with mass."}, {"id": "srp123004", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Gravitation — Orbits", "difficulty": "hard", "style": "standard", "paper": "G12-P3", "q": "Why does an astronaut in orbit experience apparent 'weightlessness', despite Earth's gravity still acting on them?", "options": ["gravity does not actually act on objects in orbit", "the astronaut and their spacecraft are both in free fall together, continuously falling toward Earth but also moving forward fast enough to continually 'miss' it", "orbiting objects are too far from Earth to feel any gravity", "weightlessness in orbit is purely an optical illusion"], "answer": 1, "exp": "An astronaut in orbit is in continuous free fall, falling toward Earth due to gravity, but moving forward fast enough that they continually 'miss' the Earth — this combination creates the sensation of apparent weightlessness, even though gravity is still acting on them.", "hint": "Think about an orbit as a continuous state of falling, combined with enough forward motion to keep missing the ground."}, {"id": "srp123005", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Gravitation — Kepler's Laws", "difficulty": "hard", "style": "standard", "paper": "G12-P3", "q": "Which best describes Kepler's third law of planetary motion?", "options": ["all planets orbit the Sun at exactly the same speed", "the square of a planet's orbital period is proportional to the cube of its average distance from the Sun", "planets orbit in perfectly circular paths with no variation", "a planet's mass determines its orbital period, with no relation to distance"], "answer": 1, "exp": "Kepler's third law states that the square of a planet's orbital period (T²) is proportional to the cube of its average orbital distance from the Sun (r³).", "hint": "Think about the specific mathematical relationship between orbital period (squared) and distance (cubed)."}, {"id": "srp123006", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Gravitation — Orbits", "difficulty": "hard", "style": "standard", "paper": "G12-P3", "q": "A satellite orbits at a radius where its orbital speed is calculated using v = √(GM/r). If the orbital radius increases, what happens to the required orbital speed?", "options": ["the required orbital speed increases", "the required orbital speed decreases", "orbital speed is completely unrelated to orbital radius", "orbital speed remains exactly the same regardless of radius"], "answer": 1, "exp": "Since orbital speed v = √(GM/r), as the orbital radius (r) increases, the required orbital speed decreases — satellites in higher orbits travel more slowly than those in lower orbits.", "hint": "Think about how r appears in the denominator inside the square root — what happens as r gets larger?"}, {"id": "srp123007", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Gravitation — Orbits", "difficulty": "hard", "style": "standard", "paper": "G12-P3", "q": "Which best describes a 'geostationary orbit'?", "options": ["an orbit where a satellite remains directly above the same point on Earth's equator at all times, due to matching Earth's rotational period", "an orbit at the lowest possible altitude above Earth", "an orbit only used for orbiting the Moon", "an orbit where a satellite's speed continuously changes unpredictably"], "answer": 0, "exp": "A geostationary orbit is one where a satellite's orbital period exactly matches Earth's rotational period (24 hours), causing it to remain directly above the same point on Earth's equator at all times.", "hint": "Think about an orbit specifically timed to match Earth's own rotation."}, {"id": "srp123008", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Special Relativity", "difficulty": "hard", "style": "standard", "paper": "G12-P3", "q": "Which best describes Einstein's postulate that 'the speed of light in a vacuum is the same for all observers, regardless of their relative motion'?", "options": ["this postulate has been experimentally disproven", "this is one of the foundational postulates of special relativity, leading to effects like time dilation and length contraction", "this postulate only applies to objects moving slower than sound", "light speed actually varies significantly depending on the observer's motion"], "answer": 1, "exp": "This is one of the two foundational postulates of Einstein's special relativity (along with the principle that the laws of physics are the same in all inertial reference frames), and it leads directly to surprising effects like time dilation and length contraction.", "hint": "Think about this as one of the core starting assumptions behind Einstein's theory."}, {"id": "srp123009", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Special Relativity — Time Dilation", "difficulty": "hard", "style": "standard", "paper": "G12-P3", "q": "Using the time dilation formula, an observer at rest measures a moving clock (travelling at 0.8c) ticking over what would be 10 seconds in the clock's own frame. Using the Lorentz factor γ ≈ 1.67 at this speed, approximately how much time does the stationary observer measure?", "options": ["6 s", "10 s", "16.7 s", "20 s"], "answer": 2, "exp": "Step 1: Dilated time = γ × proper time. Step 2: 1.67 × 10 ≈ 16.7 s, meaning the stationary observer measures more time passing than occurs in the moving clock's own frame.", "hint": "Multiply the proper time (in the moving frame) by the Lorentz factor to find the dilated time measured by the stationary observer."}, {"id": "srp123010", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Special Relativity — Time Dilation", "difficulty": "hard", "style": "standard", "paper": "G12-P3", "q": "Which best describes 'time dilation' in special relativity?", "options": ["time passes at exactly the same rate for all observers, regardless of relative motion", "a moving clock, as observed from a stationary frame, appears to run slower than a clock at rest in that stationary frame", "time dilation only applies to objects moving slower than 100 km/h", "time dilation has never been experimentally confirmed"], "answer": 1, "exp": "Time dilation describes how a moving clock, observed from a stationary reference frame, appears to run slower than an identical clock at rest in that stationary frame — an effect confirmed experimentally, including with precise atomic clocks.", "hint": "Think about how time passes differently for a moving observer compared to a stationary one, from the stationary observer's perspective."}, {"id": "srp123011", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Special Relativity — Length Contraction", "difficulty": "hard", "style": "standard", "paper": "G12-P3", "q": "An object with a proper length of 100 m travels at 0.8c. Using the length contraction formula with γ ≈ 1.67, what length would a stationary observer measure?", "options": ["40 m", "60 m", "100 m", "167 m"], "answer": 1, "exp": "Step 1: Contracted length = proper length ÷ γ. Step 2: 100 ÷ 1.67 ≈ 60 m.", "hint": "Divide the proper (rest-frame) length by the Lorentz factor."}, {"id": "srp123012", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Special Relativity — Length Contraction", "difficulty": "hard", "style": "standard", "paper": "G12-P3", "q": "Which best describes 'length contraction' in special relativity?", "options": ["objects appear longer when moving relative to an observer", "an object's length, as measured by a stationary observer, appears shorter along its direction of motion when moving at relativistic speeds", "length contraction only applies to extremely small objects", "length contraction has been completely disproven by experiment"], "answer": 1, "exp": "Length contraction describes how an object's length, as measured by a stationary observer, appears shorter along its direction of motion when that object is travelling at relativistic speeds (a significant fraction of the speed of light).", "hint": "Think about an object's measured length shrinking, specifically along the direction it's moving, from an outside observer's perspective."}, {"id": "srp123013", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Special Relativity", "difficulty": "hard", "style": "standard", "paper": "G12-P3", "q": "Why are relativistic effects like time dilation and length contraction not noticeable in everyday life?", "options": ["these effects do not actually exist", "everyday speeds are extremely small compared to the speed of light, making these effects negligibly tiny at such speeds", "relativistic effects only occur in outer space, never on Earth", "these effects only apply to objects with zero mass"], "answer": 1, "exp": "Everyday speeds (cars, planes) are extremely small compared to the speed of light, so the Lorentz factor (γ) at these speeds is so close to 1 that relativistic effects become negligibly tiny and unnoticeable in daily life.", "hint": "Think about how close the Lorentz factor is to 1 at everyday, non-relativistic speeds."}, {"id": "srp123014", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Special Relativity", "difficulty": "hard", "style": "standard", "paper": "G12-P3", "q": "What is the 'rest mass' (or 'invariant mass') of an object?", "options": ["an object's mass as measured by an observer moving relative to it", "an object's mass as measured in its own rest frame, where it is not moving", "a mass that only applies to massless particles like photons", "a mass that changes depending on the observer's frame for every type of particle"], "answer": 1, "exp": "Rest mass (or invariant mass) is an object's mass as measured in its own rest frame — the frame in which the object is not moving — and this value is the same for all observers, unlike relativistic mass concepts.", "hint": "Think about measuring an object's mass from a reference frame where the object itself isn't moving at all."}, {"id": "srp123015", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Special Relativity", "difficulty": "hard", "style": "standard", "paper": "G12-P3", "q": "Which best describes why nothing with mass can be accelerated to exactly the speed of light, according to special relativity?", "options": ["there is no actual limit on how fast a massive object can travel", "as an object's speed approaches the speed of light, the energy required to accelerate it further increases without limit, requiring infinite energy to actually reach light speed", "mass has no connection to an object's maximum possible speed", "objects with mass can easily reach light speed under normal conditions"], "answer": 1, "exp": "As an object's speed approaches the speed of light, the energy required to accelerate it further increases without limit (approaching infinity), meaning it would require infinite energy to actually reach the speed of light — making this physically impossible for any object with mass.", "hint": "Think about why the energy required for further acceleration grows so dramatically as speed approaches that of light."}, {"id": "srp123016", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Gravitation — Kepler's Laws", "difficulty": "hard", "style": "standard", "paper": "G12-P3", "q": "A satellite's orbital radius is increased so that its new radius is 4 times the original. Using Kepler's third law (T² ∝ r³), by what factor does its orbital period increase?", "options": ["2 times", "4 times", "8 times", "16 times"], "answer": 2, "exp": "Step 1: T² ∝ r³, so if r increases by a factor of 4, T² increases by a factor of 4³ = 64. Step 2: T increases by a factor of √64 = 8.", "hint": "Apply the factor increase in r to the cube relationship, then take the square root to find the factor increase in T."}, {"id": "srp123017", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Gravitation", "difficulty": "hard", "style": "standard", "paper": "G12-P3", "q": "Which best describes 'escape velocity'?", "options": ["the speed an object must reach to enter orbit around a planet", "the minimum speed needed for an object to completely escape a planet's gravitational influence without further propulsion", "the maximum speed any object can travel near a planet", "a velocity that is always the same for every planet"], "answer": 1, "exp": "Escape velocity is the minimum speed an object needs to completely escape a planet's gravitational influence (reaching an infinite distance with zero remaining kinetic energy) without any further propulsion.", "hint": "Think about the specific speed needed to break completely free from a planet's gravity, not just to orbit it."}, {"id": "srp123018", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Gravitation", "difficulty": "hard", "style": "standard", "paper": "G12-P3", "q": "Why is escape velocity from a more massive planet generally higher than from a less massive planet of similar size?", "options": ["a more massive planet exerts a stronger gravitational pull, requiring greater speed to escape it", "planet mass has no effect on escape velocity", "escape velocity depends only on a planet's distance from the Sun", "more massive planets always have lower escape velocities"], "answer": 0, "exp": "A more massive planet exerts a stronger gravitational pull on objects near its surface, requiring a greater speed to overcome that pull and escape its gravitational influence entirely.", "hint": "Think about how a stronger gravitational pull would affect the speed needed to break free from it."}, {"id": "srp123019", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "General Relativity", "difficulty": "hard", "style": "standard", "paper": "G12-P3", "q": "Which best describes the equivalence principle in general relativity?", "options": ["mass and energy are completely unrelated", "the effects of gravity are locally indistinguishable from the effects of acceleration", "gravity has no real effect on light", "general relativity completely contradicts special relativity"], "answer": 1, "exp": "The equivalence principle states that the effects of gravity are locally indistinguishable from the effects of acceleration — for example, standing in a stationary gravitational field feels identical to standing in a uniformly accelerating spacecraft.", "hint": "Think about why you might not be able to tell the difference between standing on a planet and accelerating in a spacecraft, in a small enclosed space."}, {"id": "srp123020", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "General Relativity", "difficulty": "hard", "style": "standard", "paper": "G12-P3", "q": "Which best describes 'gravitational lensing', as predicted by general relativity?", "options": ["gravity has no effect on the path of light", "massive objects can bend the path of light passing near them, due to the curvature of spacetime they cause", "gravitational lensing only affects radio waves, not visible light", "gravitational lensing has never been observed"], "answer": 1, "exp": "Gravitational lensing occurs when massive objects (like galaxies) bend the path of light passing near them, due to the curvature of spacetime caused by their mass — a key prediction of general relativity that has been observationally confirmed.", "hint": "Think about gravity's effect on light's path, due to the bending of spacetime itself around massive objects."}, {"id": "srp123021", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Special and General Relativity — Applications", "difficulty": "hard", "style": "standard", "paper": "G12-P3", "q": "Which best describes why GPS satellite systems must account for both special and general relativistic effects to maintain accuracy?", "options": ["relativistic effects are too small to matter for GPS accuracy", "GPS satellites move at high speed (special relativity) and experience weaker gravity than on Earth's surface (general relativity), both of which affect their onboard clocks measurably", "GPS systems do not use any clocks at all", "relativity has no practical applications in everyday technology"], "answer": 1, "exp": "GPS satellites move at high speed relative to Earth's surface (causing special relativistic time dilation) and experience weaker gravity at orbital altitude (causing general relativistic time effects), both of which measurably affect their onboard clocks and must be corrected for accurate positioning.", "hint": "Think about the two distinct relativistic effects — from speed and from gravity — both relevant to a satellite's clock."}, {"id": "srp123022", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Gravitation", "difficulty": "hard", "style": "standard", "paper": "G12-P3", "q": "A planet has twice the mass of Earth and the same radius. Using g = GM/r², how does its surface gravity compare to Earth's?", "options": ["half as strong", "the same strength", "twice as strong", "four times as strong"], "answer": 2, "exp": "Since g = GM/r² and radius is unchanged, doubling the mass directly doubles the surface gravitational field strength.", "hint": "Since radius stays the same, focus on how doubling the mass alone affects this formula."}, {"id": "srp123023", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Gravitation", "difficulty": "hard", "style": "standard", "paper": "G12-P3", "q": "A planet has the same mass as Earth but twice the radius. Using g = GM/r², how does its surface gravity compare to Earth's?", "options": ["one quarter as strong", "half as strong", "the same strength", "twice as strong"], "answer": 0, "exp": "Since g = GM/r², and radius is squared in the denominator, doubling the radius (with mass unchanged) reduces surface gravity to 1/2² = 1/4 of Earth's value.", "hint": "Remember that radius is squared in this formula — doubling it has a squared effect on the result."}, {"id": "srp123024", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Gravitation — Applications", "difficulty": "hard", "style": "standard", "paper": "G12-P3", "q": "Which best describes why astronauts experience significant physiological changes (such as muscle and bone density loss) during long-duration spaceflight?", "options": ["the reduced effective gravity (microgravity) during orbit means muscles and bones are not subjected to the same loads they would experience on Earth, leading to gradual loss of mass and strength", "astronauts experience increased gravity in orbit, causing these changes", "spaceflight has no measurable physiological effects on the human body", "these changes occur due to extreme temperatures in space alone"], "answer": 0, "exp": "In the reduced effective gravity (microgravity) of orbit, muscles and bones are not subjected to the same mechanical loads they experience under Earth's gravity, leading to a gradual loss of muscle and bone density over time.", "hint": "Think about what muscles and bones normally have to work against on Earth, and what's different about that in orbit."}, {"id": "srp123025", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Gravitation — Orbits", "difficulty": "hard", "style": "standard", "paper": "G12-P3", "q": "Two satellites orbit the same planet. Satellite A orbits at a smaller radius than Satellite B. Which satellite has the greater orbital speed?", "options": ["Satellite A, since orbital speed decreases with increasing radius", "Satellite B, since orbital speed increases with increasing radius", "both satellites must have exactly the same orbital speed", "orbital speed is unrelated to orbital radius"], "answer": 0, "exp": "Since orbital speed v = √(GM/r), a smaller orbital radius corresponds to a greater required orbital speed — Satellite A, orbiting closer, moves faster than Satellite B.", "hint": "Think about how orbital speed changes as radius decreases, using v = √(GM/r)."}, {"id": "srp124001", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Semiconductors", "difficulty": "hard", "style": "standard", "paper": "G12-P4", "q": "Which best describes a 'semiconductor'?", "options": ["a material that conducts electricity exactly as well as a typical metal conductor", "a material with electrical conductivity between that of a conductor and an insulator, which can be modified by adding impurities", "a material that never conducts electricity under any circumstances", "a material used only for thermal insulation"], "answer": 1, "exp": "A semiconductor has electrical conductivity between that of a conductor and an insulator, and its conductivity can be precisely controlled by adding small amounts of specific impurities (a process called doping).", "hint": "Think about a material occupying the 'middle ground' between conductors and insulators."}, {"id": "srp124002", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Semiconductors", "difficulty": "hard", "style": "standard", "paper": "G12-P4", "q": "Which best describes 'doping' in semiconductor physics?", "options": ["heating a semiconductor to extremely high temperatures", "deliberately adding small amounts of specific impurity atoms to a semiconductor to alter its electrical properties", "removing all impurities from a semiconductor", "a process used only to manufacture insulators"], "answer": 1, "exp": "Doping is the deliberate addition of small amounts of specific impurity atoms to a semiconductor, which alters its electrical properties by introducing extra charge carriers (electrons or 'holes').", "hint": "Think about deliberately adding a small amount of a different element to change a material's properties."}, {"id": "srp124003", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Semiconductors", "difficulty": "hard", "style": "standard", "paper": "G12-P4", "q": "Which best describes an 'n-type' semiconductor?", "options": ["a semiconductor doped with impurities that introduce extra free electrons as charge carriers", "a semiconductor with no charge carriers at all", "a semiconductor doped with impurities that remove all electrons", "a type of semiconductor that cannot conduct electricity under any conditions"], "answer": 0, "exp": "An n-type semiconductor is doped with impurities that introduce extra free electrons (negative charge carriers), increasing its conductivity.", "hint": "Think about the 'n' standing for 'negative', relating to the extra electrons introduced."}, {"id": "srp124004", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Semiconductors", "difficulty": "hard", "style": "standard", "paper": "G12-P4", "q": "Which best describes a 'p-type' semiconductor?", "options": ["a semiconductor doped with impurities that create extra 'holes' (positive charge carriers) due to a lack of electrons", "a semiconductor with an excess of free electrons only", "a semiconductor that cannot be doped", "a type of insulator with no charge carriers"], "answer": 0, "exp": "A p-type semiconductor is doped with impurities that create extra 'holes' — positions where an electron is missing, which behave as positive charge carriers.", "hint": "Think about the 'p' standing for 'positive', relating to these positive charge carriers."}, {"id": "srp124005", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Semiconductors — Diodes", "difficulty": "hard", "style": "standard", "paper": "G12-P4", "q": "Which best describes how a 'p-n junction diode' allows current to flow?", "options": ["it allows current to flow equally well in both directions", "it allows current to flow easily in one direction (forward bias) but strongly resists flow in the other direction (reverse bias)", "it blocks all current flow in both directions", "it only conducts when exposed to direct sunlight"], "answer": 1, "exp": "A p-n junction diode allows current to flow easily in one direction (forward bias, when the p-side is connected to the positive terminal) but strongly resists current flow in the reverse direction (reverse bias).", "hint": "Think about a one-way valve for electric current, allowing flow in only one direction."}, {"id": "srp124006", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Semiconductors — LEDs", "difficulty": "hard", "style": "standard", "paper": "G12-P4", "q": "Which best describes how a light-emitting diode (LED) produces light?", "options": ["by heating a filament until it glows", "by the recombination of electrons and holes at the p-n junction, releasing energy as photons", "by reflecting external light sources", "LEDs do not actually produce their own light"], "answer": 1, "exp": "An LED produces light when electrons and holes recombine at the p-n junction, releasing energy in the form of photons (light), with the colour determined by the semiconductor material's energy gap.", "hint": "Think about the energy released specifically when negative and positive charge carriers meet and combine."}, {"id": "srp124007", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Semiconductors — LEDs", "difficulty": "hard", "style": "standard", "paper": "G12-P4", "q": "Which best describes the main advantage of LEDs over traditional incandescent light bulbs, in terms of energy efficiency?", "options": ["LEDs convert a much higher proportion of input electrical energy into light, rather than wasted heat, compared to incandescent bulbs", "LEDs always use more electrical energy than incandescent bulbs", "LEDs produce no light output at all", "there is no meaningful efficiency difference between the two"], "answer": 0, "exp": "LEDs convert a much higher proportion of input electrical energy directly into light, rather than wasting most of it as heat (as incandescent bulbs do through their hot filament), making them significantly more energy efficient.", "hint": "Think about how much of an incandescent bulb's energy is wasted as heat, compared to an LED."}, {"id": "srp124008", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Capacitors", "difficulty": "hard", "style": "standard", "paper": "G12-P4", "q": "A capacitor with capacitance 0.001 F is charged to 10 V. Using Q = CV, what charge does it store?", "options": ["0.0001 C", "0.001 C", "0.01 C", "0.1 C"], "answer": 2, "exp": "Step 1: Q = CV. Step 2: 0.001 × 10 = 0.01 C.", "hint": "Multiply the capacitance by the voltage."}, {"id": "srp124009", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Capacitors", "difficulty": "hard", "style": "standard", "paper": "G12-P4", "q": "For the same capacitor (0.001 F, charged to 10 V), using E = ½CV², how much energy is stored?", "options": ["0.005 J", "0.01 J", "0.05 J", "0.1 J"], "answer": 2, "exp": "Step 1: E = ½CV². Step 2: ½ × 0.001 × 10² = ½ × 0.001 × 100 = 0.05 J.", "hint": "Use the formula: energy = half × capacitance × voltage squared."}, {"id": "srp124010", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Capacitors", "difficulty": "hard", "style": "standard", "paper": "G12-P4", "q": "Which best describes the main function of a capacitor in an electrical circuit?", "options": ["to store electrical energy in an electric field between its plates", "to convert electrical energy directly into heat only", "to permanently block all current flow", "to generate new electrical energy from nothing"], "answer": 0, "exp": "A capacitor's main function is to store electrical energy in the electric field created between its two charged plates, which can later be released back into the circuit.", "hint": "Think about a component designed specifically to temporarily 'hold onto' electrical energy."}, {"id": "srp124011", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Capacitors", "difficulty": "hard", "style": "standard", "paper": "G12-P4", "q": "Which best describes what happens to current flow as a capacitor charges up in a simple DC circuit?", "options": ["current increases steadily over time as the capacitor charges", "current starts high and gradually decreases as the capacitor approaches full charge", "current remains completely constant throughout the charging process", "no current ever flows while a capacitor is charging"], "answer": 1, "exp": "As a capacitor charges in a simple DC circuit, current starts relatively high and gradually decreases as the capacitor approaches full charge, since the increasing voltage across the capacitor opposes further charging current.", "hint": "Think about how the capacitor's own increasing voltage might oppose further current flow as it charges."}, {"id": "srp124012", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Capacitors", "difficulty": "hard", "style": "standard", "paper": "G12-P4", "q": "Which best describes the relationship between a capacitor's capacitance and the surface area of its plates?", "options": ["increasing plate area generally decreases capacitance", "increasing plate area generally increases capacitance, since more charge can be stored at a given voltage", "plate area has no relationship to capacitance", "capacitance depends only on the voltage applied, never on plate geometry"], "answer": 1, "exp": "Increasing a capacitor's plate area generally increases its capacitance, since a larger surface area allows more charge to be stored for a given voltage across the plates.", "hint": "Think about how more surface area might allow more charge to accumulate on the plates."}, {"id": "srp124013", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Synthesis — Energy and Power", "difficulty": "hard", "style": "standard", "paper": "G12-P4", "q": "Which best summarises the relationship between energy, power, and time, as it appears throughout physics?", "options": ["power = energy × time", "energy = power × time", "time = energy × power", "these three quantities are completely unrelated"], "answer": 1, "exp": "Energy equals power multiplied by time (E = Pt), reflecting that power is the rate at which energy is transferred or transformed.", "hint": "Think about power as a RATE of energy transfer, and what that implies about the relationship between these three quantities."}, {"id": "srp124014", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Synthesis", "difficulty": "hard", "style": "standard", "paper": "G12-P4", "q": "Which best describes why understanding both classical mechanics (e.g. Newton's laws) and quantum mechanics is necessary in modern physics?", "options": ["classical mechanics describes large-scale, everyday phenomena well, while quantum mechanics is needed to accurately describe behaviour at atomic and subatomic scales", "classical mechanics has been completely replaced and is no longer useful", "quantum mechanics applies only to large-scale astronomical objects", "there is no meaningful distinction between these two frameworks"], "answer": 0, "exp": "Classical mechanics accurately describes large-scale, everyday phenomena (like falling objects or orbiting planets), while quantum mechanics is needed to accurately describe behaviour at atomic and subatomic scales, where classical predictions break down.", "hint": "Think about the different scales at which each framework provides the most accurate predictions."}, {"id": "srp124015", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Synthesis — Semiconductors and Quantum Physics", "difficulty": "hard", "style": "standard", "paper": "G12-P4", "q": "Which best describes why solar panels (photovoltaic cells) are able to generate electricity from sunlight?", "options": ["they directly heat water to drive a generator", "they use the photoelectric effect within semiconductor material to release electrons when struck by photons of sufficient energy, generating an electric current", "they store chemical energy from sunlight for later release", "solar panels do not actually use any semiconductor materials"], "answer": 1, "exp": "Solar panels use the photoelectric effect within semiconductor material (typically silicon), where photons of sufficient energy release electrons, generating a usable electric current directly from sunlight.", "hint": "Think about the same underlying physical effect explored earlier in relation to electron emission from a surface."}, {"id": "srp124016", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Synthesis — Energy Conservation", "difficulty": "hard", "style": "standard", "paper": "G12-P4", "q": "Which best describes why a transformer (relying on electromagnetic induction) cannot be used to directly increase the TOTAL energy delivered by a circuit?", "options": ["transformers actually do create additional energy from nothing", "transformers only change the relative proportions of voltage and current; total power (and hence energy, ignoring losses) remains essentially unchanged, consistent with energy conservation", "transformers always reduce total energy to zero", "this is not actually true — transformers do increase total energy"], "answer": 1, "exp": "Transformers change the relative proportions of voltage and current (stepping one up while stepping the other down), but the total power delivered (and thus energy, ignoring small losses) remains essentially unchanged, consistent with the law of conservation of energy.", "hint": "Think about how transformers trade off voltage against current, rather than creating any new total energy."}, {"id": "srp124017", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Synthesis — Nuclear Physics", "difficulty": "hard", "style": "standard", "paper": "G12-P4", "q": "Which best describes why nuclear fusion is generally considered a promising future energy source, despite current technological challenges?", "options": ["fusion produces no usable energy at all", "fusion has the potential to release large amounts of energy from abundant fuel sources (like hydrogen isotopes), with comparatively less long-lived radioactive waste than fission", "fusion reactions can already be sustained easily and cheaply on Earth", "fusion is identical to fission in every respect"], "answer": 1, "exp": "Fusion has the potential to release large amounts of energy from relatively abundant fuel sources (such as hydrogen isotopes), while generally producing comparatively less long-lived radioactive waste than fission — though significant technological challenges remain in sustaining controlled fusion reactions on Earth.", "hint": "Think about the potential benefits of fusion, balanced against the genuine technical challenges still being worked on."}, {"id": "srp124018", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Capacitors", "difficulty": "hard", "style": "standard", "paper": "G12-P4", "q": "A circuit contains both a resistor and a capacitor in series (an RC circuit), connected to a DC voltage source. What happens to the capacitor's voltage over time as it charges?", "options": ["it increases rapidly at first, then gradually levels off as it approaches the supply voltage", "it remains at zero throughout the entire charging process", "it increases at a perfectly constant, unchanging rate", "it decreases steadily over time"], "answer": 0, "exp": "In an RC charging circuit, the capacitor's voltage increases rapidly at first, then gradually levels off (approaching the supply voltage asymptotically) as the capacitor approaches full charge.", "hint": "Think about the charging curve gradually flattening out, rather than rising at a constant rate."}, {"id": "srp124019", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Capacitors — Applications", "difficulty": "hard", "style": "standard", "paper": "G12-P4", "q": "Which best describes a practical application of capacitors in everyday electronic devices?", "options": ["capacitors are never used in practical electronic devices", "capacitors are commonly used to smooth out voltage fluctuations, store energy for brief bursts of power, and filter signals in circuits", "capacitors can only be used in very large-scale industrial equipment", "capacitors are used exclusively to generate light"], "answer": 1, "exp": "Capacitors are commonly used in everyday electronics to smooth out voltage fluctuations, store energy for brief bursts of power (such as in a camera flash), and filter unwanted signals in circuits.", "hint": "Think about a few common, practical roles capacitors play in devices you might use daily."}, {"id": "srp124020", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Synthesis — Quantum Physics", "difficulty": "hard", "style": "standard", "paper": "G12-P4", "q": "Which best describes why understanding wave-particle duality is important in modern physics?", "options": ["it shows that light and matter exhibit both wave-like and particle-like properties, depending on the experiment or context", "wave-particle duality has been completely disproven", "only light exhibits wave-particle duality, never matter", "this concept has no real experimental support"], "answer": 0, "exp": "Wave-particle duality shows that both light and matter can exhibit wave-like properties (such as interference) and particle-like properties (such as discrete energy packets), depending on the specific experiment or context — a foundational concept in quantum mechanics.", "hint": "Think about how the same entity, like light, can show behaviour associated with both waves AND particles, depending on how it's observed."}, {"id": "srp124021", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Synthesis", "difficulty": "hard", "style": "standard", "paper": "G12-P4", "q": "Which best describes why an understanding of energy transformations (e.g. electrical to mechanical, chemical to electrical) is central to many areas of physics covered across a senior physics course?", "options": ["energy transformations are only relevant to one narrow topic within physics", "energy and its transformations provide a unifying framework connecting mechanics, electricity, thermodynamics, and modern physics, since the same conservation principles apply throughout", "each area of physics uses a completely separate, unrelated concept of energy", "energy is not actually a useful concept in modern physics"], "answer": 1, "exp": "Energy and its transformations provide a unifying framework connecting seemingly different areas of physics — mechanics, electricity, thermodynamics, and modern physics — since the same fundamental conservation principles apply consistently throughout all of them.", "hint": "Think about how the same core concept (energy, and its conservation) keeps reappearing across very different topics in physics."}, {"id": "srp124022", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Synthesis — Nature of Science", "difficulty": "hard", "style": "standard", "paper": "G12-P4", "q": "Which best describes why scientists continue to refine and test established physical theories, such as general relativity, even after extensive prior confirmation?", "options": ["scientific theories should never be tested once accepted", "science continually seeks to test theories under new conditions and with greater precision, since even well-established theories could in principle be refined or shown to have limits", "testing established theories serves no scientific purpose", "once a theory is accepted, it can never be revised under any circumstances"], "answer": 1, "exp": "Science continually seeks to test established theories under new conditions and with ever greater precision, since even very well-confirmed theories could, in principle, be refined, extended, or shown to have limits under conditions not yet fully explored.", "hint": "Think about why ongoing testing remains valuable, even for theories that have already passed many previous tests."}, {"id": "srp124023", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Capacitors", "difficulty": "hard", "style": "standard", "paper": "G12-P4", "q": "Using Q = CV, a capacitor stores 0.02 C of charge at 4 V. What is its capacitance?", "options": ["0.005 F", "0.05 F", "0.08 F", "0.5 F"], "answer": 0, "exp": "Step 1: C = Q/V. Step 2: 0.02 ÷ 4 = 0.005 F.", "hint": "Rearrange Q = CV to solve for capacitance."}, {"id": "srp124024", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Synthesis", "difficulty": "hard", "style": "standard", "paper": "G12-P4", "q": "Which best describes why combining knowledge from mechanics, electromagnetism, thermodynamics, and quantum physics is often necessary to fully explain modern technologies, such as a smartphone?", "options": ["a single isolated area of physics is always sufficient to explain any modern device", "modern devices often rely on multiple physical principles working together — for example, semiconductors (quantum physics), circuits (electromagnetism), and heat management (thermodynamics) — making an integrated understanding valuable", "modern technology has no real connection to fundamental physics", "combining different areas of physics has no practical benefit"], "answer": 1, "exp": "Modern devices like smartphones rely on multiple physical principles working together — including semiconductor physics (quantum mechanics), electrical circuits (electromagnetism), and heat management (thermodynamics) — making an integrated understanding across these areas genuinely valuable.", "hint": "Think about a smartphone, and how many different areas of physics might be involved in just making it function."}, {"id": "srp124025", "state": "AU", "section": "sr_physics", "grade": "12", "topic": "Capacitors", "difficulty": "hard", "style": "standard", "paper": "G12-P4", "q": "A capacitor with a capacitance of 0.002 F is charged to 6 V. Using E = ½CV², how much energy is stored?", "options": ["0.006 J", "0.012 J", "0.024 J", "0.036 J"], "answer": 3, "exp": "Step 1: E = ½CV². Step 2: ½ × 0.002 × 6² = ½ × 0.002 × 36 = 0.036 J.", "hint": "Use the formula: energy = half × capacitance × voltage squared."}];